{
  "name": "JobTrack AI",
  "description": "Smart work time tracker with AI-powered activity logging and overtime analysis."
}

export interface WorkSession {
  id: string;
  startTime: string; // ISO string
  endTime: string | null; // ISO string
  activityRaw: string;
  activityRefined: string;
  tags: string[];
}

export interface DailyStat {
  date: string; // YYYY-MM-DD
  totalHours: number;
  expectedHours: number;
  overtime: number; // Can be negative
}

export interface UserSettings {
  dailyTargetHours: number;
  hourlyRate?: number;
}

import { WorkSession, UserSettings } from '../types';

const SESSIONS_KEY = 'jobtrack_sessions';
const SETTINGS_KEY = 'jobtrack_settings';

export const loadSessions = (): WorkSession[] => {
  try {
    const data = localStorage.getItem(SESSIONS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load sessions", e);
    return [];
  }
};

export const saveSessions = (sessions: WorkSession[]) => {
  localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
};

export const loadSettings = (): UserSettings => {
  try {
    const data = localStorage.getItem(SETTINGS_KEY);
    return data ? JSON.parse(data) : { dailyTargetHours: 8 };
  } catch (e) {
    return { dailyTargetHours: 8 };
  }
};

export const saveSettings = (settings: UserSettings) => {
  localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
};

import { GoogleGenAI } from "@google/genai";
import { WorkSession } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const refineActivityText = async (rawText: string): Promise<string> => {
  if (!apiKey) return rawText;
  if (!rawText.trim()) return "";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional assistant. Rewrite the following rough work log into a concise, professional bulleted list in Italian. Remove emotion, focus on tasks.

      Input: "${rawText}"

      Output (Markdown):`,
    });

    return response.text || rawText;
  } catch (error) {
    console.error("Gemini refinement error:", error);
    return rawText;
  }
};

export const generateWeeklyReport = async (sessions: WorkSession[]): Promise<string> => {
  if (!apiKey) return "API Key mancante. Impossibile generare report.";

  // Prepare simplified data for the prompt
  const dataSummary = sessions.map(s => ({
    date: new Date(s.startTime).toLocaleDateString('it-IT'),
    duration: s.endTime ? (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / 1000 / 3600 : 0,
    tasks: s.activityRefined || s.activityRaw
  })).slice(-10); // Last 10 sessions to keep context small

  const prompt = `Analizza i seguenti dati sulle sessioni di lavoro recenti e fornisci un breve riepilogo in Italiano (max 100 parole) evidenziando le aree principali di focus e la produttività.

  Dati: ${JSON.stringify(dataSummary)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Impossibile generare il report.";
  } catch (error) {
    return "Errore durante la generazione del report.";
  }
};

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell } from 'recharts';
import { WorkSession, UserSettings } from '../types';

interface WorkChartProps {
  sessions: WorkSession[];
  settings: UserSettings;
}

const WorkChart: React.FC<WorkChartProps> = ({ sessions, settings }) => {
  const data = useMemo(() => {
    // Aggregate by day
    const dayMap = new Map<string, number>();

    // Sort sessions by date first
    const sortedSessions = [...sessions].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

    sortedSessions.forEach(session => {
      if (!session.endTime) return;
      const dateKey = new Date(session.startTime).toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' });
      const durationHours = (new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60);

      dayMap.set(dateKey, (dayMap.get(dateKey) || 0) + durationHours);
    });

    // Take last 7 days with activity
    return Array.from(dayMap.entries()).slice(-7).map(([date, hours]) => ({
      date,
      hours: parseFloat(hours.toFixed(2)),
      target: settings.dailyTargetHours
    }));
  }, [sessions, settings]);

  if (data.length === 0) {
    return <div className="text-center text-slate-400 py-10">Nessun dato disponibile per il grafico.</div>;
  }

  return (
    <div className="h-64 w-full mt-4">
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data} margin={{ top: 5, right: 30, left: -20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={false} />
          <XAxis dataKey="date" tick={{ fontSize: 12 }} stroke="#64748b" />
          <YAxis tick={{ fontSize: 12 }} stroke="#64748b" />
          <Tooltip 
            cursor={{ fill: '#f1f5f9' }}
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
          />
          <ReferenceLine y={settings.dailyTargetHours} stroke="#ef4444" strokeDasharray="3 3" label={{ position: 'top', value: 'Target', fill: '#ef4444', fontSize: 10 }} />
          <Bar dataKey="hours" radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.hours >= entry.target ? '#22c55e' : '#3b82f6'} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default WorkChart;

import React, { useState, useEffect } from 'react';

interface TimerDisplayProps {
  startTime: string;
}

const TimerDisplay: React.FC<TimerDisplayProps> = ({ startTime }) => {
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    const start = new Date(startTime).getTime();
    const interval = setInterval(() => {
      setElapsed(Date.now() - start);
    }, 1000);

    return () => clearInterval(interval);
  }, [startTime]);

  const formatTime = (ms: number) => {
    const totalSeconds = Math.floor(ms / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;
    return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  };

  return (
    <div className="font-mono text-5xl md:text-6xl font-bold text-slate-800 tracking-tighter tabular-nums">
      {formatTime(elapsed)}
    </div>
  );
};

export default TimerDisplay;

import React, { useState, useEffect, useCallback } from 'react';
import { Play, Square, Clock, Calendar, BarChart2, Settings, Sparkles, Check, Trash2 } from 'lucide-react';
import { WorkSession, UserSettings } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import WorkChart from './components/WorkChart';
import TimerDisplay from './components/TimerDisplay';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [settings, setSettings] = useState<UserSettings>({ dailyTargetHours: 8 });
  const [view, setView] = useState<'dashboard' | 'history' | 'settings'>('dashboard');

  // UI State for Activity Editing
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [activityText, setActivityText] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Initialize
  useEffect(() => {
    const loadedSessions = Storage.loadSessions();
    const loadedSettings = Storage.loadSettings();
    setSessions(loadedSessions);
    setSettings(loadedSettings);

    // Check for open session
    const openSession = loadedSessions.find(s => s.endTime === null);
    if (openSession) {
      setCurrentSessionId(openSession.id);
    }
  }, []);

  // Persist sessions whenever they change
  useEffect(() => {
    Storage.saveSessions(sessions);
  }, [sessions]);

  // Persist settings
  useEffect(() => {
    Storage.saveSettings(settings);
  }, [settings]);

  // --- Logic ---

  const handleStartWork = () => {
    const newSession: WorkSession = {
      id: crypto.randomUUID(),
      startTime: new Date().toISOString(),
      endTime: null,
      activityRaw: '',
      activityRefined: '',
      tags: []
    };
    setSessions(prev => [...prev, newSession]);
    setCurrentSessionId(newSession.id);
  };

  const handleStopWork = () => {
    if (!currentSessionId) return;

    const now = new Date().toISOString();
    setSessions(prev => prev.map(s => 
      s.id === currentSessionId ? { ...s, endTime: now } : s
    ));

    // Auto open edit modal for the just-finished session
    setEditingSessionId(currentSessionId);
    setActivityText('');
    setCurrentSessionId(null);
  };

  const handleSaveActivity = async (sessionId: string) => {
    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: activityText } : s
    ));
    setEditingSessionId(null);
    setActivityText('');
  };

  const handleRefineWithAI = async (sessionId: string) => {
    setIsAiLoading(true);
    const refined = await GeminiService.refineActivityText(activityText);

    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: refined } : s
    ));
    setActivityText(refined); // Update local input too
    setIsAiLoading(false);
  };

  const handleDeleteSession = (id: string) => {
    if (confirm("Sei sicuro di voler eliminare questa sessione?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
      if (currentSessionId === id) setCurrentSessionId(null);
    }
  };

  const generateReport = async () => {
    setIsAiLoading(true);
    const report = await GeminiService.generateWeeklyReport(sessions);
    setAiReport(report);
    setIsAiLoading(false);
  };

  // --- Derived Data ---

  const currentSession = sessions.find(s => s.id === currentSessionId);

  const todayDate = new Date().toLocaleDateString('it-IT');
  const todaysSessions = sessions.filter(s => new Date(s.startTime).toLocaleDateString('it-IT') === todayDate);
  const totalMsToday = todaysSessions.reduce((acc, s) => {
    const end = s.endTime ? new Date(s.endTime).getTime() : Date.now();
    return acc + (end - new Date(s.startTime).getTime());
  }, 0);
  const totalHoursToday = totalMsToday / (1000 * 60 * 60);
  const overtimeToday = totalHoursToday - settings.dailyTargetHours;

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 text-white p-1.5 rounded-lg">
              <Clock size={20} strokeWidth={2.5} />
            </div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight">JobTrack AI</h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-slate-100 rounded text-slate-500">
            {todayDate}
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-6">

        {/* --- DASHBOARD VIEW --- */}
        {view === 'dashboard' && (
          <>
            {/* Timer Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8 flex flex-col items-center justify-center space-y-6 relative overflow-hidden">
              <div className={`absolute top-0 left-0 w-full h-1 ${currentSession ? 'bg-blue-500 animate-pulse' : 'bg-slate-200'}`}></div>

              <div className="text-center space-y-2">
                <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold uppercase tracking-wider ${currentSession ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'}`}>
                  {currentSession ? <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"/> : null}
                  {currentSession ? 'In Corso' : 'Pausa'}
                </span>
                {currentSession ? (
                  <TimerDisplay startTime={currentSession.startTime} />
                ) : (
                  <div className="font-mono text-5xl md:text-6xl font-bold text-slate-300 tracking-tighter">00:00:00</div>
                )}
                <p className="text-slate-500 text-sm">
                  Oggi hai lavorato <span className="font-medium text-slate-900">{totalHoursToday.toFixed(2)}h</span> su {settings.dailyTargetHours}h
                </p>
              </div>

              <button
                onClick={currentSession ? handleStopWork : handleStartWork}
                className={`w-full max-w-xs h-14 rounded-xl flex items-center justify-center gap-2 text-lg font-semibold transition-all shadow-lg active:scale-95 ${
                  currentSession 
                  ? 'bg-red-50 text-red-600 border border-red-200 hover:bg-red-100' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200'
                }`}
              >
                {currentSession ? (
                  <> <Square size={20} fill="currentColor" /> Termina Lavoro </>
                ) : (
                  <> <Play size={24} fill="currentColor" /> Inizia Turno </>
                )}
              </button>
            </div>

            {/* Stats Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                  <BarChart2 size={18} /> Statistiche Settimanali
                </h2>
                <div className={`text-sm font-bold ${overtimeToday >= 0 ? 'text-green-600' : 'text-orange-500'}`}>
                  {overtimeToday > 0 ? '+' : ''}{overtimeToday.toFixed(2)}h Straordinario Oggi
                </div>
              </div>
              <WorkChart sessions={sessions} settings={settings} />
            </div>

            {/* Recent Sessions */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Sessioni Recenti</h3>
                <button 
                  onClick={generateReport}
                  disabled={isAiLoading}
                  className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-700 font-medium disabled:opacity-50"
                >
                  <Sparkles size={14} /> {isAiLoading ? 'Analisi...' : 'Analisi AI'}
                </button>
               </div>

               {aiReport && (
                 <div className="bg-purple-50 border border-purple-100 p-4 rounded-xl text-sm text-purple-900 leading-relaxed mb-4 animate-in fade-in slide-in-from-top-2">
                   <h4 className="font-bold mb-1 flex items-center gap-2"><Sparkles size={12} /> Insight Gemini</h4>
                   {aiReport}
                 </div>
               )}

               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className="bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-blue-300 group">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="text-sm font-medium text-slate-900">
                          {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ' ...'}
                        </div>
                        <div className="text-xs text-slate-500 mt-0.5">
                          {new Date(session.startTime).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                         <span className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-slate-600">
                           {session.endTime 
                             ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                             : 'In corso'}
                         </span>
                         <button onClick={() => handleDeleteSession(session.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                           <Trash2 size={14} />
                         </button>
                      </div>
                    </div>

                    <div className="relative">
                       {editingSessionId === session.id ? (
                         <div className="space-y-2">
                           <textarea
                             value={activityText}
                             onChange={(e) => setActivityText(e.target.value)}
                             placeholder="Cosa hai fatto in questa sessione?"
                             className="w-full text-sm p-3 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-slate-50"
                             rows={3}
                             autoFocus
                           />
                           <div className="flex gap-2 justify-end">
                             <button 
                               onClick={() => handleRefineWithAI(session.id)}
                               disabled={isAiLoading || !activityText}
                               className="text-xs bg-purple-100 text-purple-700 px-3 py-1.5 rounded-md font-medium flex items-center gap-1 hover:bg-purple-200 disabled:opacity-50"
                             >
                               <Sparkles size={12} /> {isAiLoading ? 'Migliorando...' : 'Migliora con AI'}
                             </button>
                             <button 
                               onClick={() => handleSaveActivity(session.id)}
                               className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium hover:bg-blue-700"
                             >
                               Salva
                             </button>
                           </div>
                         </div>
                       ) : (
                         <div 
                           onClick={() => {
                             setEditingSessionId(session.id);
                             setActivityText(session.activityRefined || session.activityRaw);
                           }}
                           className={`text-sm cursor-pointer hover:bg-slate-50 p-2 -ml-2 rounded-lg transition-colors ${!session.activityRefined && !session.activityRaw ? 'text-slate-400 italic' : 'text-slate-700'}`}
                         >
                           {session.activityRefined || session.activityRaw || "Tocca per aggiungere attività..."}
                         </div>
                       )}
                    </div>
                  </div>
                ))}
                {sessions.length === 0 && (
                  <div className="text-center py-10 text-slate-400 text-sm">Nessuna sessione registrata. Inizia a lavorare!</div>
                )}
               </div>
            </div>
          </>
        )}

        {/* --- HISTORY VIEW --- */}
        {view === 'history' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h2 className="font-bold text-lg mb-6 flex items-center gap-2"><Calendar size={20} /> Storico Completo</h2>
            <div className="space-y-4">
              {sessions.sort((a,b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()).map(session => (
                 <div key={session.id} className="border-b border-slate-100 pb-4 last:border-0 last:pb-0">
                    <div className="flex justify-between mb-1">
                      <span className="font-medium text-slate-900">{new Date(session.startTime).toLocaleDateString()}</span>
                      <span className="font-mono text-sm text-slate-500">
                         {session.endTime 
                           ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                           : 'In corso'}
                      </span>
                    </div>
                    <div className="text-sm text-slate-600">
                      {session.activityRefined || session.activityRaw || <span className="text-slate-400 italic">Nessuna descrizione</span>}
                    </div>
                 </div>
              ))}
            </div>
          </div>
        )}

        {/* --- SETTINGS VIEW --- */}
        {view === 'settings' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
            <h2 className="font-bold text-lg flex items-center gap-2"><Settings size={20} /> Impostazioni</h2>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">Ore target giornaliere</label>
              <input 
                type="number" 
                value={settings.dailyTargetHours}
                onChange={(e) => setSettings({...settings, dailyTargetHours: Number(e.target.value)})}
                className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
              />
              <p className="text-xs text-slate-500 mt-1">Usato per calcolare lo straordinario.</p>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <h3 className="font-medium text-slate-900 mb-2">Dati</h3>
              <button 
                onClick={() => {
                  if(confirm('Cancellare tutti i dati? Questa azione è irreversibile.')) {
                    setSessions([]);
                    Storage.saveSessions([]);
                  }
                }}
                className="text-red-600 text-sm hover:underline flex items-center gap-1"
              >
                <Trash2 size={14} /> Cancella tutti i dati
              </button>
            </div>

            <div className="bg-blue-50 p-4 rounded-lg text-sm text-blue-800">
              <p className="font-semibold mb-1">Info API AI</p>
              <p>L'app usa Google Gemini per riassumere le attività. Assicurati che l'API key sia configurata correttamente nell'ambiente se stai sviluppando localmente.</p>
            </div>
          </div>
        )}

      </main>

      {/* Mobile Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-20 md:hidden">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Clock size={24} /> Home
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'history' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Calendar size={24} /> Storico
        </button>
        <button 
          onClick={() => setView('settings')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'settings' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Settings size={24} /> Opzioni
        </button>
      </nav>

      {/* Desktop Navigation Hints (Hidden on mobile) */}
      <div className="hidden md:flex fixed top-4 right-4 z-20 gap-2">
         <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'dashboard' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Dashboard</button>
         <button onClick={() => setView('history')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'history' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Storico</button>
         <button onClick={() => setView('settings')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'settings' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Opzioni</button>
      </div>

    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface WorkSession {
  id: string;
  startTime: string; // ISO string
  endTime: string | null; // ISO string
  activityRaw: string;
  activityRefined: string;
  tags: string[];
}

export interface DailyStat {
  date: string; // YYYY-MM-DD
  totalHours: number;
  expectedHours: number;
  overtime: number; // Can be negative
}

export interface ScheduleSettings {
  monThu: number; // Target hours for Mon-Thu
  fri: number;    // Target hours for Fri
  satSun: number; // Target hours for Sat-Sun
}

export interface UserSettings {
  schedule: ScheduleSettings;
  hourlyRate?: number;
}

import { UserSettings } from '../types';

// Fixed Italian Holidays (DD-MM)
const FIXED_HOLIDAYS = new Set([
  '01-01', // Capodanno
  '01-06', // Epifania
  '04-25', // Liberazione
  '05-01', // Festa del Lavoro
  '06-02', // Repubblica
  '08-15', // Ferragosto
  '11-01', // Ognissanti
  '12-08', // Immacolata
  '12-25', // Natale
  '12-26', // Santo Stefano
]);

export const isHoliday = (date: Date): boolean => {
  const dayMonth = date.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' }).replace('/', '-');
  return FIXED_HOLIDAYS.has(dayMonth);
};

export const getTargetHoursForDate = (dateString: string, settings: UserSettings): number => {
  const date = new Date(dateString);
  const day = date.getDay(); // 0 = Sun, 1 = Mon, ... 6 = Sat

  // Check Holidays first
  if (isHoliday(date)) {
    return settings.schedule.satSun; // Treat holidays like weekends (usually 0)
  }

  // Sunday (0) or Saturday (6)
  if (day === 0 || day === 6) {
    return settings.schedule.satSun;
  }

  // Friday (5)
  if (day === 5) {
    return settings.schedule.fri;
  }

  // Mon (1) - Thu (4)
  return settings.schedule.monThu;
};

import { WorkSession, UserSettings } from '../types';

const SESSIONS_KEY = 'jobtrack_sessions';
const SETTINGS_KEY = 'jobtrack_settings';

// Default schedule: Mon-Thu 8.5h (08:00-16:30), Fri 4h (08:00-12:00), Weekend 0
const DEFAULT_SETTINGS: UserSettings = {
  schedule: {
    monThu: 8.5,
    fri: 4,
    satSun: 0
  }
};

export const loadSessions = (): WorkSession[] => {
  try {
    const data = localStorage.getItem(SESSIONS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load sessions", e);
    return [];
  }
};

export const saveSessions = (sessions: WorkSession[]) => {
  localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
};

export const loadSettings = (): UserSettings => {
  try {
    const data = localStorage.getItem(SETTINGS_KEY);
    if (!data) return DEFAULT_SETTINGS;

    const parsed = JSON.parse(data);

    // Migration: If old settings format (dailyTargetHours), convert to new structure
    if (typeof parsed.dailyTargetHours === 'number') {
       return {
         ...DEFAULT_SETTINGS,
         // We ignore the old flat value in favor of the new structure defaults 
         // unless we want to map it, but the user asked specifically for the new schedule.
       };
    }

    return { ...DEFAULT_SETTINGS, ...parsed };
  } catch (e) {
    return DEFAULT_SETTINGS;
  }
};

export const saveSettings = (settings: UserSettings) => {
  localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
};

import React, { useMemo } from 'react';
import { ComposedChart, Line, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, Legend } from 'recharts';
import { WorkSession, UserSettings } from '../types';
import { getTargetHoursForDate } from '../services/dateService';

interface WorkChartProps {
  sessions: WorkSession[];
  settings: UserSettings;
}

const WorkChart: React.FC<WorkChartProps> = ({ sessions, settings }) => {
  const data = useMemo(() => {
    // Aggregate by day
    const dayMap = new Map<string, { hours: number; dateFull: string }>();

    // Initialize last 7 days to ensure gaps are shown correctly (e.g. 0 hours worked)
    const today = new Date();
    for (let i = 6; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dateKey = d.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' });
      dayMap.set(dateKey, { hours: 0, dateFull: d.toISOString() });
    }

    // Sort sessions
    const sortedSessions = [...sessions].sort((a, b) => new Date(a.startTime).getTime() - new Date(b.startTime).getTime());

    sortedSessions.forEach(session => {
      if (!session.endTime) return;
      const dateKey = new Date(session.startTime).toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' });

      // Only process if within our 7-day window (or simply update existing keys)
      if (dayMap.has(dateKey)) {
        const current = dayMap.get(dateKey)!;
        const durationHours = (new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60);
        current.hours += durationHours;
      }
    });

    // Convert to array
    return Array.from(dayMap.entries()).map(([date, info]) => {
      const target = getTargetHoursForDate(info.dateFull, settings);
      return {
        date,
        hours: parseFloat(info.hours.toFixed(2)),
        target: target,
        overtime: parseFloat((info.hours - target).toFixed(2))
      };
    });
  }, [sessions, settings]);

  if (data.length === 0) {
    return <div className="text-center text-slate-400 py-10">Nessun dato disponibile per il grafico.</div>;
  }

  return (
    <div className="h-64 w-full mt-4">
      <ResponsiveContainer width="100%" height="100%">
        <ComposedChart data={data} margin={{ top: 5, right: 0, left: -20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={false} />
          <XAxis dataKey="date" tick={{ fontSize: 12 }} stroke="#94a3b8" />
          <YAxis tick={{ fontSize: 12 }} stroke="#94a3b8" />
          <Tooltip 
            cursor={{ fill: '#f8fafc' }}
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            formatter={(value: number, name: string) => [
              `${value}h`, 
              name === 'hours' ? 'Lavorato' : 'Obiettivo'
            ]}
          />
          <Legend iconSize={10} wrapperStyle={{fontSize: '12px', paddingTop: '10px'}}/>

          <Bar dataKey="hours" name="Lavorato" barSize={20} radius={[4, 4, 0, 0]}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.hours >= entry.target ? '#22c55e' : (entry.hours > 0 ? '#3b82f6' : '#e2e8f0')} />
            ))}
          </Bar>

          {/* Target Line - Stepped to show clear differences between Fri/Mon */}
          <Line 
            type="stepAfter" 
            dataKey="target" 
            name="Obiettivo" 
            stroke="#ef4444" 
            strokeWidth={2} 
            dot={{ r: 3, fill: '#ef4444', strokeWidth: 0 }} 
            strokeDasharray="4 4"
            activeDot={{ r: 5 }}
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  );
};

export default WorkChart;

