               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className="bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-blue-300 group">
