                   return acc + (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
                 }, 0);

                 // Reconstruct a Date object from the locale string DD/MM/YYYY for target calculation
                 // Note: Ideally we store ISO strings in the keys, but for display this works if consistent
                 const [d, m, y] = dayStr.split('/').map(Number);
                 const dateObj = new Date(y, m-1, d);
