          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Clock size={24} /> Home
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'history' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Calendar size={24} /> Storico
        </button>
        <button 
          onClick={() => setView('settings')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'settings' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Settings size={24} /> Opzioni
        </button>
      </nav>

      {/* Desktop Navigation Hints (Hidden on mobile) */}
      <div className="hidden md:flex fixed top-4 right-4 z-20 gap-2">
         <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'dashboard' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Dashboard</button>
         <button onClick={() => setView('history')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'history' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Storico</button>
         <button onClick={() => setView('settings')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'settings' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Opzioni</button>
      </div>

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Save, Clock, Calendar, BarChart2, Settings, Sparkles, Trash2, Info, TrendingUp, TrendingDown, AlertCircle } from 'lucide-react';
import { WorkSession, UserSettings } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import * as DateService from './services/dateService';
import WorkChart from './components/WorkChart';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [settings, setSettings] = useState<UserSettings>({ 
    schedule: { monThu: 8.5, fri: 4, satSun: 0 } 
  });

  const [view, setView] = useState<'dashboard' | 'history' | 'settings'>('dashboard');

  // Manual Entry State
  const [entryDate, setEntryDate] = useState(new Date().toISOString().split('T')[0]);
  const [entryStart, setEntryStart] = useState('08:00');
  const [entryEnd, setEntryEnd] = useState('16:30');
  const [entryActivity, setEntryActivity] = useState('');

  // UI State for Activity Editing / AI
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [activityText, setActivityText] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Initialize
  useEffect(() => {
    const loadedSessions = Storage.loadSessions();
    const loadedSettings = Storage.loadSettings();
    setSessions(loadedSessions);
    setSettings(loadedSettings);
  }, []);

  // Persist sessions whenever they change
  useEffect(() => {
    Storage.saveSessions(sessions);
  }, [sessions]);

  // Persist settings
  useEffect(() => {
    Storage.saveSettings(settings);
  }, [settings]);

  // --- Logic ---

  const handleAddManualSession = async () => {
    if (!entryDate || !entryStart || !entryEnd) return;

    const startDateTime = new Date(`${entryDate}T${entryStart}`);
    const endDateTime = new Date(`${entryDate}T${entryEnd}`);

    if (endDateTime <= startDateTime) {
      alert("L'orario di fine deve essere successivo all'inizio.");
      return;
    }

    const newSession: WorkSession = {
      id: crypto.randomUUID(),
      startTime: startDateTime.toISOString(),
      endTime: endDateTime.toISOString(),
      activityRaw: entryActivity,
      activityRefined: entryActivity,
      tags: []
    };

    setSessions(prev => [...prev, newSession]);

    // Reset activity but keep times/date for easier sequential entry
    setEntryActivity('');

    // AI Refinement Trigger
    if (entryActivity) {
       setIsAiLoading(true);
       try {
         const refined = await GeminiService.refineActivityText(entryActivity);
         setSessions(prev => prev.map(s => s.id === newSession.id ? { ...s, activityRefined: refined } : s));
       } catch(e) { console.error(e) }
       setIsAiLoading(false);
    }
  };

  const handleSaveActivity = async (sessionId: string) => {
    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: activityText } : s
    ));
    setEditingSessionId(null);
    setActivityText('');
  };

  const handleRefineWithAI = async (sessionId: string) => {
    setIsAiLoading(true);
    const refined = await GeminiService.refineActivityText(activityText);

    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: refined } : s
    ));
    setActivityText(refined); 
    setIsAiLoading(false);
  };

  const handleDeleteSession = (id: string) => {
    if (confirm("Sei sicuro di voler eliminare questa sessione?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
    }
  };

  const generateReport = async () => {
    setIsAiLoading(true);
    const report = await GeminiService.generateWeeklyReport(sessions);
    setAiReport(report);
    setIsAiLoading(false);
  };

  // --- Derived Data ---

  const todayDateStr = new Date().toISOString();
  const todayLocale = new Date().toLocaleDateString('it-IT');

  // Today's Stats (calculated based on manual entries for "today")
  const todaysSessions = sessions.filter(s => new Date(s.startTime).toLocaleDateString('it-IT') === todayLocale);
  const totalMsToday = todaysSessions.reduce((acc, s) => {
    const end = s.endTime ? new Date(s.endTime).getTime() : Date.now();
    return acc + (end - new Date(s.startTime).getTime());
  }, 0);

  const totalHoursToday = totalMsToday / (1000 * 60 * 60);
  const targetToday = DateService.getTargetHoursForDate(todayDateStr, settings);
  const overtimeToday = totalHoursToday - targetToday;

  // Total Balance (Monte Ore)
  const totalBalance = DateService.calculateTotalBalance(sessions, settings);

  // Grouped History for Display
  const sessionsByDay = sessions.reduce((acc, session) => {
    const day = new Date(session.startTime).toLocaleDateString('it-IT');
    if (!acc[day]) acc[day] = [];
    acc[day].push(session);
    return acc;
  }, {} as Record<string, WorkSession[]>);

  const sortedDays = Object.keys(sessionsByDay).sort((a, b) => {
    const [da, ma, ya] = a.split('/').map(Number);
    const [db, mb, yb] = b.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const isEntryDateHoliday = DateService.isHoliday(new Date(entryDate));

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 text-white p-1.5 rounded-lg">
              <Clock size={20} strokeWidth={2.5} />
            </div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight">JobTrack AI</h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-slate-100 rounded text-slate-500">
            {todayLocale}
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-6">

        {/* --- DASHBOARD VIEW --- */}
        {view === 'dashboard' && (
          <>
            {/* Balances Grid - Moved to Top */}
            <div className="grid grid-cols-2 gap-4">
                {/* Monte Ore Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center relative overflow-hidden">
                  <div className={`absolute top-0 left-0 w-1 h-full ${totalBalance >= 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Monte Ore Totale</div>
                  <div className={`text-3xl font-bold flex items-center gap-2 ${totalBalance >= 0 ? 'text-green-700' : 'text-red-600'}`}>
                    {totalBalance >= 0 ? <TrendingUp size={28} /> : <TrendingDown size={28} />}
                    {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}h
                  </div>
                  <div className="text-xs text-slate-400 mt-1">Saldo accumulato globale</div>
                </div>

                {/* Daily Stat Small Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center">
                   <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Saldo Oggi</div>
                   <div className={`text-3xl font-bold ${overtimeToday >= 0 ? 'text-blue-600' : 'text-orange-500'}`}>
                     {overtimeToday > 0 ? '+' : ''}{overtimeToday.toFixed(2)}h
                   </div>
                   <div className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                    su {targetToday}h previste
                    {DateService.isHoliday(new Date()) && <span className="text-orange-500" title="Festivo">✨</span>}
                   </div>
                </div>
            </div>

            {/* Manual Entry Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative">
              <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 border-b border-slate-100 pb-3">
                <Plus size={20} className="text-blue-600" /> Registra Attività
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-5 mb-5">
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Data</label>
                   <input 
                    type="date" 
                    value={entryDate} 
                    onChange={e => setEntryDate(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                   {isEntryDateHoliday && (
                     <div className="text-xs text-orange-600 font-medium mt-1 flex items-center gap-1">
                       <Sparkles size={10} /> Giorno Festivo
                     </div>
                   )}
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Inizio</label>
                   <input 
                    type="time" 
                    value={entryStart} 
                    onChange={e => setEntryStart(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Fine</label>
                   <input 
                    type="time" 
                    value={entryEnd} 
                    onChange={e => setEntryEnd(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
              </div>

              <div className="mb-5">
                  <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Descrizione Attività (Opzionale)</label>
                  <input 
                    type="text" 
                    value={entryActivity} 
                    onChange={e => setEntryActivity(e.target.value)}
                    placeholder="Es. Sviluppo funzionalità login..." 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm placeholder:text-slate-400"
                  />
              </div>

              <button 
                onClick={handleAddManualSession}
                className="w-full bg-blue-600 text-white font-semibold py-3 rounded-xl shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-[0.99] transition-all flex items-center justify-center gap-2"
              >
                <Save size={18} /> Salva Registrazione
              </button>
            </div>

            {/* Stats Chart */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                  <BarChart2 size={18} /> Grafico Settimanale
                </h2>
              </div>
              <WorkChart sessions={sessions} settings={settings} />
            </div>

            {/* Recent Sessions List */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Registrazioni Recenti</h3>
                <button 
                  onClick={generateReport}
                  disabled={isAiLoading}
                  className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-700 font-medium disabled:opacity-50"
                >
                  <Sparkles size={14} /> {isAiLoading ? 'Analisi...' : 'Report AI'}
                </button>
               </div>

               {aiReport && (
                 <div className="bg-purple-50 border border-purple-100 p-4 rounded-xl text-sm text-purple-900 leading-relaxed mb-4 animate-in fade-in slide-in-from-top-2">
                   <h4 className="font-bold mb-1 flex items-center gap-2"><Sparkles size={12} /> Insight Gemini</h4>
                   {aiReport}
                 </div>
               )}

               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className="bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-blue-300 group">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="text-sm font-medium text-slate-900">
                          {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ' ...'}
                        </div>
                        <div className="text-xs text-slate-500 mt-0.5">
                          {new Date(session.startTime).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                         <span className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-slate-600">
                           {session.endTime 
                             ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                             : 'N/A'}
                         </span>
                         <button onClick={() => handleDeleteSession(session.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                           <Trash2 size={14} />
                         </button>
                      </div>
                    </div>

                    <div className="relative">
                       {editingSessionId === session.id ? (
                         <div className="space-y-2">
                           <textarea
                             value={activityText}
                             onChange={(e) => setActivityText(e.target.value)}
                             placeholder="Modifica attività..."
                             className="w-full text-sm p-3 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-slate-50"
                             rows={3}
                             autoFocus
                           />
                           <div className="flex gap-2 justify-end">
                             <button 
                               onClick={() => handleRefineWithAI(session.id)}
                               disabled={isAiLoading || !activityText}
                               className="text-xs bg-purple-100 text-purple-700 px-3 py-1.5 rounded-md font-medium flex items-center gap-1 hover:bg-purple-200 disabled:opacity-50"
                             >
                               <Sparkles size={12} /> {isAiLoading ? '...' : 'AI'}
                             </button>
                             <button 
                               onClick={() => handleSaveActivity(session.id)}
                               className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium hover:bg-blue-700"
                             >
                               Salva
                             </button>
                           </div>
                         </div>
                       ) : (
                         <div 
                           onClick={() => {
                             setEditingSessionId(session.id);
                             setActivityText(session.activityRefined || session.activityRaw);
                           }}
                           className={`text-sm cursor-pointer hover:bg-slate-50 p-2 -ml-2 rounded-lg transition-colors ${!session.activityRefined && !session.activityRaw ? 'text-slate-400 italic' : 'text-slate-700'}`}
                         >
                           {session.activityRefined || session.activityRaw || "Aggiungi descrizione..."}
                         </div>
                       )}
                    </div>
                  </div>
                ))}
                {sessions.length === 0 && (
                  <div className="text-center py-10 text-slate-400 text-sm">Nessuna registrazione presente.</div>
                )}
               </div>
            </div>
          </>
        )}

        {/* --- HISTORY VIEW --- */}
        {view === 'history' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h2 className="font-bold text-lg mb-6 flex items-center gap-2"><Calendar size={20} /> Storico Completo</h2>
            <div className="space-y-6">
              {sortedDays.reverse().map(dayStr => {
                 // Calculate daily total for this day
                 const daysSessions = sessionsByDay[dayStr];
                 const dayTotal = daysSessions.reduce((acc, s) => {
                   if (!s.endTime) return acc;
                   return acc + (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
                 }, 0);

                 const [d, m, y] = dayStr.split('/').map(Number);
                 const dateObj = new Date(y, m-1, d);
                 const target = DateService.getTargetHoursForDate(dateObj.toISOString(), settings);
                 const delta = dayTotal - target;
                 const isHoliday = DateService.isHoliday(dateObj);

                 return (
                  <div key={dayStr} className="space-y-2">
                    <div className="flex items-center justify-between bg-slate-50 p-2 rounded-lg">
                      <div className="flex items-center gap-2">
                         <div className="font-semibold text-slate-700 text-sm">{dayStr}</div>
                         {isHoliday && <span className="text-xs text-orange-500 font-bold px-1.5 py-0.5 bg-orange-100 rounded">FESTIVO</span>}
                      </div>
                      <div className="flex items-center gap-3">
                         <span className={`text-xs font-bold ${delta >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                           {delta > 0 ? '+' : ''}{delta.toFixed(2)}h
                         </span>
                         <span className="text-sm font-mono text-slate-900 bg-white px-2 py-0.5 rounded border border-slate-200">
                           Tot: {dayTotal.toFixed(2)}h
                         </span>
                      </div>
                    </div>

                    <div className="pl-4 space-y-3 border-l-2 border-slate-100 ml-2">
                      {daysSessions.sort((a,b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()).map(session => (
                        <div key={session.id} className="relative pb-1">
                            <div className="flex justify-between mb-0.5">
                              <span className="text-xs text-slate-500 font-medium">
                                {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                                {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '...'}
                              </span>
                            </div>
                            <div className="text-sm text-slate-600">
                              {session.activityRefined || session.activityRaw || <span className="text-slate-400 italic text-xs">Nessuna descrizione</span>}
                            </div>
                        </div>
                      ))}
                    </div>
                  </div>
                 );
              })}
              {sessions.length === 0 && <div className="text-center text-slate-400 text-sm">Nessuno storico disponibile.</div>}
            </div>
          </div>
        )}

        {/* --- SETTINGS VIEW --- */}
        {view === 'settings' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
            <h2 className="font-bold text-lg flex items-center gap-2"><Settings size={20} /> Impostazioni</h2>

            <div className="space-y-4">
              <h3 className="font-medium text-slate-800 text-sm uppercase tracking-wide">Orario di Lavoro Standard</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Lun - Gio</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.monThu}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, monThu: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Venerdì</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.fri}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, fri: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Weekend / Festivi</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.satSun}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, satSun: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
              </div>
              <div className="flex items-start gap-2 bg-slate-50 p-3 rounded-lg text-xs text-slate-600">
                <Info size={16} className="text-blue-500 shrink-0 mt-0.5" />
                <p>I giorni festivi italiani (Natale, Capodanno, ecc.) sono rilevati automaticamente e useranno l'orario "Weekend / Festivi". Le ore lavorate in questi giorni sono considerate interamente come straordinario nel monte ore.</p>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <h3 className="font-medium text-slate-900 mb-2">Dati</h3>
              <button 
                onClick={() => {
                  if(confirm('Cancellare tutti i dati? Questa azione è irreversibile.')) {
                    setSessions([]);
                    Storage.saveSessions([]);
                  }
                }}
                className="text-red-600 text-sm hover:underline flex items-center gap-1"
              >
                <Trash2 size={14} /> Cancella tutti i dati
              </button>
            </div>
          </div>
        )}

      </main>

      {/* Mobile Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-20 md:hidden">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Clock size={24} /> Home
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'history' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Calendar size={24} /> Storico
        </button>
        <button 
          onClick={() => setView('settings')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'settings' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Settings size={24} /> Opzioni
        </button>
      </nav>

      {/* Desktop Navigation Hints (Hidden on mobile) */}
      <div className="hidden md:flex fixed top-4 right-4 z-20 gap-2">
         <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'dashboard' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Dashboard</button>
         <button onClick={() => setView('history')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'history' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Storico</button>
         <button onClick={() => setView('settings')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'settings' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Opzioni</button>
      </div>

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Save, Clock, Calendar, BarChart2, Settings, Sparkles, Trash2, Info, TrendingUp, TrendingDown, AlertCircle } from 'lucide-react';
import { WorkSession, UserSettings } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import * as DateService from './services/dateService';
import WorkChart from './components/WorkChart';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [settings, setSettings] = useState<UserSettings>({ 
    schedule: { monThu: 8.5, fri: 4, satSun: 0 } 
  });

  const [view, setView] = useState<'dashboard' | 'history' | 'settings'>('dashboard');

  // Manual Entry State
  const [entryDate, setEntryDate] = useState(new Date().toISOString().split('T')[0]);
  const [entryStart, setEntryStart] = useState('08:00');
  const [entryEnd, setEntryEnd] = useState('16:30');
  const [entryActivity, setEntryActivity] = useState('');

  // UI State for Activity Editing / AI
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [activityText, setActivityText] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Initialize
  useEffect(() => {
    const loadedSessions = Storage.loadSessions();
    const loadedSettings = Storage.loadSettings();
    setSessions(loadedSessions);
    setSettings(loadedSettings);
  }, []);

  // Persist sessions whenever they change
  useEffect(() => {
    Storage.saveSessions(sessions);
  }, [sessions]);

  // Persist settings
  useEffect(() => {
    Storage.saveSettings(settings);
  }, [settings]);

  // --- Logic ---

  const handleAddManualSession = async () => {
    if (!entryDate || !entryStart || !entryEnd) return;

    const startDateTime = new Date(`${entryDate}T${entryStart}`);
    const endDateTime = new Date(`${entryDate}T${entryEnd}`);

    if (endDateTime <= startDateTime) {
      alert("L'orario di fine deve essere successivo all'inizio.");
      return;
    }

    const newSession: WorkSession = {
      id: crypto.randomUUID(),
      startTime: startDateTime.toISOString(),
      endTime: endDateTime.toISOString(),
      activityRaw: entryActivity,
      activityRefined: entryActivity,
      tags: []
    };

    setSessions(prev => [...prev, newSession]);

    // Reset ALL fields to default state
    setEntryDate(new Date().toISOString().split('T')[0]);
    setEntryStart('08:00');
    setEntryEnd('16:30');
    setEntryActivity('');

    // AI Refinement Trigger
    if (entryActivity) {
       setIsAiLoading(true);
       try {
         const refined = await GeminiService.refineActivityText(entryActivity);
         setSessions(prev => prev.map(s => s.id === newSession.id ? { ...s, activityRefined: refined } : s));
       } catch(e) { console.error(e) }
       setIsAiLoading(false);
    }
  };

  const handleSaveActivity = async (sessionId: string) => {
    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: activityText } : s
    ));
    setEditingSessionId(null);
    setActivityText('');
  };

  const handleRefineWithAI = async (sessionId: string) => {
    setIsAiLoading(true);
    const refined = await GeminiService.refineActivityText(activityText);

    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: refined } : s
    ));
    setActivityText(refined); 
    setIsAiLoading(false);
  };

  const handleDeleteSession = (id: string) => {
    if (confirm("Sei sicuro di voler eliminare questa sessione?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
    }
  };

  const generateReport = async () => {
    setIsAiLoading(true);
    const report = await GeminiService.generateWeeklyReport(sessions);
    setAiReport(report);
    setIsAiLoading(false);
  };

  // --- Derived Data ---

  const todayDateStr = new Date().toISOString();
  const todayLocale = new Date().toLocaleDateString('it-IT');

  // Today's Stats (calculated based on manual entries for "today")
  const todaysSessions = sessions.filter(s => new Date(s.startTime).toLocaleDateString('it-IT') === todayLocale);
  const totalMsToday = todaysSessions.reduce((acc, s) => {
    const end = s.endTime ? new Date(s.endTime).getTime() : Date.now();
    return acc + (end - new Date(s.startTime).getTime());
  }, 0);

  const totalHoursToday = totalMsToday / (1000 * 60 * 60);
  const targetToday = DateService.getTargetHoursForDate(todayDateStr, settings);
  const overtimeToday = totalHoursToday - targetToday;

  // Total Balance (Monte Ore)
  const totalBalance = DateService.calculateTotalBalance(sessions, settings);

  // Grouped History for Display
  const sessionsByDay = sessions.reduce((acc, session) => {
    const day = new Date(session.startTime).toLocaleDateString('it-IT');
    if (!acc[day]) acc[day] = [];
    acc[day].push(session);
    return acc;
  }, {} as Record<string, WorkSession[]>);

  const sortedDays = Object.keys(sessionsByDay).sort((a, b) => {
    const [da, ma, ya] = a.split('/').map(Number);
    const [db, mb, yb] = b.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const isEntryDateHoliday = DateService.isHoliday(new Date(entryDate));

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 text-white p-1.5 rounded-lg">
              <Clock size={20} strokeWidth={2.5} />
            </div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight">JobTrack AI</h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-slate-100 rounded text-slate-500">
            {todayLocale}
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-6">

        {/* --- DASHBOARD VIEW --- */}
        {view === 'dashboard' && (
          <>
            {/* Balances Grid - Moved to Top */}
            <div className="grid grid-cols-2 gap-4">
                {/* Monte Ore Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center relative overflow-hidden">
                  <div className={`absolute top-0 left-0 w-1 h-full ${totalBalance >= 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Monte Ore Totale</div>
                  <div className={`text-3xl font-bold flex items-center gap-2 ${totalBalance >= 0 ? 'text-green-700' : 'text-red-600'}`}>
                    {totalBalance >= 0 ? <TrendingUp size={28} /> : <TrendingDown size={28} />}
                    {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}h
                  </div>
                  <div className="text-xs text-slate-400 mt-1">Saldo accumulato globale</div>
                </div>

                {/* Daily Stat Small Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center">
                   <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Saldo Oggi</div>
                   <div className={`text-3xl font-bold ${overtimeToday >= 0 ? 'text-blue-600' : 'text-orange-500'}`}>
                     {overtimeToday > 0 ? '+' : ''}{overtimeToday.toFixed(2)}h
                   </div>
                   <div className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                    su {targetToday}h previste
                    {DateService.isHoliday(new Date()) && <span className="text-orange-500" title="Festivo">✨</span>}
                   </div>
                </div>
            </div>

            {/* Manual Entry Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative">
              <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 border-b border-slate-100 pb-3">
                <Plus size={20} className="text-blue-600" /> Registra Attività
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-5 mb-5">
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Data</label>
                   <input 
                    type="date" 
                    value={entryDate} 
                    onChange={e => setEntryDate(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                   {isEntryDateHoliday && (
                     <div className="text-xs text-orange-600 font-medium mt-1 flex items-center gap-1">
                       <Sparkles size={10} /> Giorno Festivo
                     </div>
                   )}
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Inizio</label>
                   <input 
                    type="time" 
                    value={entryStart} 
                    onChange={e => setEntryStart(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Fine</label>
                   <input 
                    type="time" 
                    value={entryEnd} 
                    onChange={e => setEntryEnd(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
              </div>

              <div className="mb-5">
                  <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Descrizione Attività (Opzionale)</label>
                  <input 
                    type="text" 
                    value={entryActivity} 
                    onChange={e => setEntryActivity(e.target.value)}
                    placeholder="Es. Sviluppo funzionalità login..." 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm placeholder:text-slate-400"
                  />
              </div>

              <button 
                onClick={handleAddManualSession}
                className="w-full bg-blue-600 text-white font-semibold py-3 rounded-xl shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-[0.99] transition-all flex items-center justify-center gap-2"
              >
                <Save size={18} /> Salva Registrazione
              </button>
            </div>

            {/* Stats Chart */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                  <BarChart2 size={18} /> Grafico Settimanale
                </h2>
              </div>
              <WorkChart sessions={sessions} settings={settings} />
            </div>

            {/* Recent Sessions List */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Registrazioni Recenti</h3>
                <button 
                  onClick={generateReport}
                  disabled={isAiLoading}
                  className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-700 font-medium disabled:opacity-50"
                >
                  <Sparkles size={14} /> {isAiLoading ? 'Analisi...' : 'Report AI'}
                </button>
               </div>

               {aiReport && (
                 <div className="bg-purple-50 border border-purple-100 p-4 rounded-xl text-sm text-purple-900 leading-relaxed mb-4 animate-in fade-in slide-in-from-top-2">
                   <h4 className="font-bold mb-1 flex items-center gap-2"><Sparkles size={12} /> Insight Gemini</h4>
                   {aiReport}
                 </div>
               )}

               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className="bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-blue-300 group">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="text-sm font-medium text-slate-900">
                          {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ' ...'}
                        </div>
                        <div className="text-xs text-slate-500 mt-0.5">
                          {new Date(session.startTime).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                         <span className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-slate-600">
                           {session.endTime 
                             ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                             : 'N/A'}
                         </span>
                         <button onClick={() => handleDeleteSession(session.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                           <Trash2 size={14} />
                         </button>
                      </div>
                    </div>

                    <div className="relative">
                       {editingSessionId === session.id ? (
                         <div className="space-y-2">
                           <textarea
                             value={activityText}
                             onChange={(e) => setActivityText(e.target.value)}
                             placeholder="Modifica attività..."
                             className="w-full text-sm p-3 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-slate-50"
                             rows={3}
                             autoFocus
                           />
                           <div className="flex gap-2 justify-end">
                             <button 
                               onClick={() => handleRefineWithAI(session.id)}
                               disabled={isAiLoading || !activityText}
                               className="text-xs bg-purple-100 text-purple-700 px-3 py-1.5 rounded-md font-medium flex items-center gap-1 hover:bg-purple-200 disabled:opacity-50"
                             >
                               <Sparkles size={12} /> {isAiLoading ? '...' : 'AI'}
                             </button>
                             <button 
                               onClick={() => handleSaveActivity(session.id)}
                               className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium hover:bg-blue-700"
                             >
                               Salva
                             </button>
                           </div>
                         </div>
                       ) : (
                         <div 
                           onClick={() => {
                             setEditingSessionId(session.id);
                             setActivityText(session.activityRefined || session.activityRaw);
                           }}
                           className={`text-sm cursor-pointer hover:bg-slate-50 p-2 -ml-2 rounded-lg transition-colors ${!session.activityRefined && !session.activityRaw ? 'text-slate-400 italic' : 'text-slate-700'}`}
                         >
                           {session.activityRefined || session.activityRaw || "Aggiungi descrizione..."}
                         </div>
                       )}
                    </div>
                  </div>
                ))}
                {sessions.length === 0 && (
                  <div className="text-center py-10 text-slate-400 text-sm">Nessuna registrazione presente.</div>
                )}
               </div>
            </div>
          </>
        )}

        {/* --- HISTORY VIEW --- */}
        {view === 'history' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h2 className="font-bold text-lg mb-6 flex items-center gap-2"><Calendar size={20} /> Storico Completo</h2>
            <div className="space-y-6">
              {sortedDays.reverse().map(dayStr => {
                 // Calculate daily total for this day
                 const daysSessions = sessionsByDay[dayStr];
                 const dayTotal = daysSessions.reduce((acc, s) => {
                   if (!s.endTime) return acc;
                   return acc + (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
                 }, 0);

                 const [d, m, y] = dayStr.split('/').map(Number);
                 const dateObj = new Date(y, m-1, d);
                 const target = DateService.getTargetHoursForDate(dateObj.toISOString(), settings);
                 const delta = dayTotal - target;
                 const isHoliday = DateService.isHoliday(dateObj);

                 return (
                  <div key={dayStr} className="space-y-2">
                    <div className="flex items-center justify-between bg-slate-50 p-2 rounded-lg">
                      <div className="flex items-center gap-2">
                         <div className="font-semibold text-slate-700 text-sm">{dayStr}</div>
                         {isHoliday && <span className="text-xs text-orange-500 font-bold px-1.5 py-0.5 bg-orange-100 rounded">FESTIVO</span>}
                      </div>
                      <div className="flex items-center gap-3">
                         <span className={`text-xs font-bold ${delta >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                           {delta > 0 ? '+' : ''}{delta.toFixed(2)}h
                         </span>
                         <span className="text-sm font-mono text-slate-900 bg-white px-2 py-0.5 rounded border border-slate-200">
                           Tot: {dayTotal.toFixed(2)}h
                         </span>
                      </div>
                    </div>

                    <div className="pl-4 space-y-3 border-l-2 border-slate-100 ml-2">
                      {daysSessions.sort((a,b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()).map(session => (
                        <div key={session.id} className="relative pb-1">
                            <div className="flex justify-between mb-0.5">
                              <span className="text-xs text-slate-500 font-medium">
                                {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                                {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '...'}
                              </span>
                            </div>
                            <div className="text-sm text-slate-600">
                              {session.activityRefined || session.activityRaw || <span className="text-slate-400 italic text-xs">Nessuna descrizione</span>}
                            </div>
                        </div>
                      ))}
                    </div>
                  </div>
                 );
              })}
              {sessions.length === 0 && <div className="text-center text-slate-400 text-sm">Nessuno storico disponibile.</div>}
            </div>
          </div>
        )}

        {/* --- SETTINGS VIEW --- */}
        {view === 'settings' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
            <h2 className="font-bold text-lg flex items-center gap-2"><Settings size={20} /> Impostazioni</h2>

            <div className="space-y-4">
              <h3 className="font-medium text-slate-800 text-sm uppercase tracking-wide">Orario di Lavoro Standard</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Lun - Gio</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.monThu}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, monThu: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Venerdì</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.fri}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, fri: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Weekend / Festivi</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.satSun}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, satSun: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
              </div>
              <div className="flex items-start gap-2 bg-slate-50 p-3 rounded-lg text-xs text-slate-600">
                <Info size={16} className="text-blue-500 shrink-0 mt-0.5" />
                <p>I giorni festivi italiani (Natale, Capodanno, ecc.) sono rilevati automaticamente e useranno l'orario "Weekend / Festivi". Le ore lavorate in questi giorni sono considerate interamente come straordinario nel monte ore.</p>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <h3 className="font-medium text-slate-900 mb-2">Dati</h3>
              <button 
                onClick={() => {
                  if(confirm('Cancellare tutti i dati? Questa azione è irreversibile.')) {
                    setSessions([]);
                    Storage.saveSessions([]);
                  }
                }}
                className="text-red-600 text-sm hover:underline flex items-center gap-1"
              >
                <Trash2 size={14} /> Cancella tutti i dati
              </button>
            </div>
          </div>
        )}

      </main>

      {/* Mobile Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-20 md:hidden">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Clock size={24} /> Home
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'history' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Calendar size={24} /> Storico
        </button>
        <button 
          onClick={() => setView('settings')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'settings' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Settings size={24} /> Opzioni
        </button>
      </nav>

      {/* Desktop Navigation Hints (Hidden on mobile) */}
      <div className="hidden md:flex fixed top-4 right-4 z-20 gap-2">
         <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'dashboard' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Dashboard</button>
         <button onClick={() => setView('history')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'history' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Storico</button>
         <button onClick={() => setView('settings')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'settings' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Opzioni</button>
      </div>

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Save, Clock, Calendar, BarChart2, Settings, Sparkles, Trash2, Info, TrendingUp, TrendingDown, AlertCircle } from 'lucide-react';
import { WorkSession, UserSettings } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import * as DateService from './services/dateService';
import WorkChart from './components/WorkChart';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [settings, setSettings] = useState<UserSettings>({ 
    schedule: { monThu: 8.5, fri: 4, satSun: 0 } 
  });

  const [view, setView] = useState<'dashboard' | 'history' | 'settings'>('dashboard');

  // Manual Entry State
  const [entryDate, setEntryDate] = useState(new Date().toISOString().split('T')[0]);
  const [entryStart, setEntryStart] = useState('08:00');
  const [entryEnd, setEntryEnd] = useState('16:30');
  const [entryActivity, setEntryActivity] = useState('');

  // UI State for Activity Editing / AI
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [activityText, setActivityText] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Initialize
  useEffect(() => {
    const loadedSessions = Storage.loadSessions();
    const loadedSettings = Storage.loadSettings();
    setSessions(loadedSessions);
    setSettings(loadedSettings);
  }, []);

  // Persist sessions whenever they change
  useEffect(() => {
    Storage.saveSessions(sessions);
  }, [sessions]);

  // Persist settings
  useEffect(() => {
    Storage.saveSettings(settings);
  }, [settings]);

  // --- Logic ---

  const handleAddManualSession = async () => {
    if (!entryDate || !entryStart || !entryEnd) return;

    const startDateTime = new Date(`${entryDate}T${entryStart}`);
    const endDateTime = new Date(`${entryDate}T${entryEnd}`);

    if (endDateTime <= startDateTime) {
      alert("L'orario di fine deve essere successivo all'inizio.");
      return;
    }

    const newSession: WorkSession = {
      id: crypto.randomUUID(),
      startTime: startDateTime.toISOString(),
      endTime: endDateTime.toISOString(),
      activityRaw: entryActivity,
      activityRefined: entryActivity,
      tags: []
    };

    setSessions(prev => [...prev, newSession]);

    // Reset activity but keep times/date for easier sequential entry
    setEntryActivity('');

    // AI Refinement Trigger
    if (entryActivity) {
       setIsAiLoading(true);
       try {
         const refined = await GeminiService.refineActivityText(entryActivity);
         setSessions(prev => prev.map(s => s.id === newSession.id ? { ...s, activityRefined: refined } : s));
       } catch(e) { console.error(e) }
       setIsAiLoading(false);
    }
  };

  const handleSaveActivity = async (sessionId: string) => {
    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: activityText } : s
    ));
    setEditingSessionId(null);
    setActivityText('');
  };

  const handleRefineWithAI = async (sessionId: string) => {
    setIsAiLoading(true);
    const refined = await GeminiService.refineActivityText(activityText);

    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: refined } : s
    ));
    setActivityText(refined); 
    setIsAiLoading(false);
  };

  const handleDeleteSession = (id: string) => {
    if (confirm("Sei sicuro di voler eliminare questa sessione?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
    }
  };

  const generateReport = async () => {
    setIsAiLoading(true);
    const report = await GeminiService.generateWeeklyReport(sessions);
    setAiReport(report);
    setIsAiLoading(false);
  };

  // --- Derived Data ---

  const todayDateStr = new Date().toISOString();
  const todayLocale = new Date().toLocaleDateString('it-IT');

  // Today's Stats (calculated based on manual entries for "today")
  const todaysSessions = sessions.filter(s => new Date(s.startTime).toLocaleDateString('it-IT') === todayLocale);
  const totalMsToday = todaysSessions.reduce((acc, s) => {
    const end = s.endTime ? new Date(s.endTime).getTime() : Date.now();
    return acc + (end - new Date(s.startTime).getTime());
  }, 0);

  const totalHoursToday = totalMsToday / (1000 * 60 * 60);
  const targetToday = DateService.getTargetHoursForDate(todayDateStr, settings);
  const overtimeToday = totalHoursToday - targetToday;

  // Total Balance (Monte Ore)
  const totalBalance = DateService.calculateTotalBalance(sessions, settings);

  // Grouped History for Display
  const sessionsByDay = sessions.reduce((acc, session) => {
    const day = new Date(session.startTime).toLocaleDateString('it-IT');
    if (!acc[day]) acc[day] = [];
    acc[day].push(session);
    return acc;
  }, {} as Record<string, WorkSession[]>);

  const sortedDays = Object.keys(sessionsByDay).sort((a, b) => {
    const [da, ma, ya] = a.split('/').map(Number);
    const [db, mb, yb] = b.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const isEntryDateHoliday = DateService.isHoliday(new Date(entryDate));

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 text-white p-1.5 rounded-lg">
              <Clock size={20} strokeWidth={2.5} />
            </div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight">JobTrack AI</h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-slate-100 rounded text-slate-500">
            {todayLocale}
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-6">

        {/* --- DASHBOARD VIEW --- */}
        {view === 'dashboard' && (
          <>
            {/* Balances Grid - Moved to Top */}
            <div className="grid grid-cols-2 gap-4">
                {/* Monte Ore Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center relative overflow-hidden">
                  <div className={`absolute top-0 left-0 w-1 h-full ${totalBalance >= 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Monte Ore Totale</div>
                  <div className={`text-3xl font-bold flex items-center gap-2 ${totalBalance >= 0 ? 'text-green-700' : 'text-red-600'}`}>
                    {totalBalance >= 0 ? <TrendingUp size={28} /> : <TrendingDown size={28} />}
                    {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}h
                  </div>
                  <div className="text-xs text-slate-400 mt-1">Saldo accumulato globale</div>
                </div>

                {/* Daily Stat Small Card */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-5 flex flex-col justify-center">
                   <div className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-1">Saldo Oggi</div>
                   <div className={`text-3xl font-bold ${overtimeToday >= 0 ? 'text-blue-600' : 'text-orange-500'}`}>
                     {overtimeToday > 0 ? '+' : ''}{overtimeToday.toFixed(2)}h
                   </div>
                   <div className="text-xs text-slate-400 mt-1 flex items-center gap-1">
                    su {targetToday}h previste
                    {DateService.isHoliday(new Date()) && <span className="text-orange-500" title="Festivo">✨</span>}
                   </div>
                </div>
            </div>

            {/* Manual Entry Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative">
              <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 border-b border-slate-100 pb-3">
                <Plus size={20} className="text-blue-600" /> Registra Attività
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-5 mb-5">
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Data</label>
                   <input 
                    type="date" 
                    value={entryDate} 
                    onChange={e => setEntryDate(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                   {isEntryDateHoliday && (
                     <div className="text-xs text-orange-600 font-medium mt-1 flex items-center gap-1">
                       <Sparkles size={10} /> Giorno Festivo
                     </div>
                   )}
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Inizio</label>
                   <input 
                    type="time" 
                    value={entryStart} 
                    onChange={e => setEntryStart(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Ora Fine</label>
                   <input 
                    type="time" 
                    value={entryEnd} 
                    onChange={e => setEntryEnd(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                </div>
              </div>

              <div className="mb-5">
                  <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Descrizione Attività (Opzionale)</label>
                  <input 
                    type="text" 
                    value={entryActivity} 
                    onChange={e => setEntryActivity(e.target.value)}
                    placeholder="Es. Sviluppo funzionalità login..." 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm placeholder:text-slate-400"
                  />
              </div>

              <button 
                onClick={handleAddManualSession}
                className="w-full bg-blue-600 text-white font-semibold py-3 rounded-xl shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-[0.99] transition-all flex items-center justify-center gap-2"
              >
                <Save size={18} /> Salva Registrazione
              </button>
            </div>

            {/* Stats Chart */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                  <BarChart2 size={18} /> Grafico Settimanale
                </h2>
              </div>
              <WorkChart sessions={sessions} settings={settings} />
            </div>

            {/* Recent Sessions List */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Registrazioni Recenti</h3>
                <button 
                  onClick={generateReport}
                  disabled={isAiLoading}
                  className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-700 font-medium disabled:opacity-50"
                >
                  <Sparkles size={14} /> {isAiLoading ? 'Analisi...' : 'Report AI'}
                </button>
               </div>

               {aiReport && (
                 <div className="bg-purple-50 border border-purple-100 p-4 rounded-xl text-sm text-purple-900 leading-relaxed mb-4 animate-in fade-in slide-in-from-top-2">
                   <h4 className="font-bold mb-1 flex items-center gap-2"><Sparkles size={12} /> Insight Gemini</h4>
                   {aiReport}
                 </div>
               )}

               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className="bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 transition-colors hover:border-blue-300 group">
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="text-sm font-medium text-slate-900">
                          {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ' ...'}
                        </div>
                        <div className="text-xs text-slate-500 mt-0.5">
                          {new Date(session.startTime).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                         <span className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-slate-600">
                           {session.endTime 
                             ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                             : 'N/A'}
                         </span>
                         <button onClick={() => handleDeleteSession(session.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
                           <Trash2 size={14} />
                         </button>
                      </div>
                    </div>

                    <div className="relative">
                       {editingSessionId === session.id ? (
                         <div className="space-y-2">
                           <textarea
                             value={activityText}
                             onChange={(e) => setActivityText(e.target.value)}
                             placeholder="Modifica attività..."
                             className="w-full text-sm p-3 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-slate-50"
                             rows={3}
                             autoFocus
                           />
                           <div className="flex gap-2 justify-end">
                             <button 
                               onClick={() => handleRefineWithAI(session.id)}
                               disabled={isAiLoading || !activityText}
                               className="text-xs bg-purple-100 text-purple-700 px-3 py-1.5 rounded-md font-medium flex items-center gap-1 hover:bg-purple-200 disabled:opacity-50"
                             >
                               <Sparkles size={12} /> {isAiLoading ? '...' : 'AI'}
                             </button>
                             <button 
                               onClick={() => handleSaveActivity(session.id)}
                               className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium hover:bg-blue-700"
                             >
                               Salva
                             </button>
                           </div>
                         </div>
                       ) : (
                         <div 
                           onClick={() => {
                             setEditingSessionId(session.id);
                             setActivityText(session.activityRefined || session.activityRaw);
                           }}
                           className={`text-sm cursor-pointer hover:bg-slate-50 p-2 -ml-2 rounded-lg transition-colors ${!session.activityRefined && !session.activityRaw ? 'text-slate-400 italic' : 'text-slate-700'}`}
                         >
                           {session.activityRefined || session.activityRaw || "Aggiungi descrizione..."}
                         </div>
                       )}
                    </div>
                  </div>
                ))}
                {sessions.length === 0 && (
                  <div className="text-center py-10 text-slate-400 text-sm">Nessuna registrazione presente.</div>
                )}
               </div>
            </div>
          </>
        )}

        {/* --- HISTORY VIEW --- */}
        {view === 'history' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h2 className="font-bold text-lg mb-6 flex items-center gap-2"><Calendar size={20} /> Storico Completo</h2>
            <div className="space-y-6">
              {sortedDays.reverse().map(dayStr => {
                 // Calculate daily total for this day
                 const daysSessions = sessionsByDay[dayStr];
                 const dayTotal = daysSessions.reduce((acc, s) => {
                   if (!s.endTime) return acc;
                   return acc + (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
                 }, 0);

                 const [d, m, y] = dayStr.split('/').map(Number);
                 const dateObj = new Date(y, m-1, d);
                 const target = DateService.getTargetHoursForDate(dateObj.toISOString(), settings);
                 const delta = dayTotal - target;
                 const isHoliday = DateService.isHoliday(dateObj);

                 return (
                  <div key={dayStr} className="space-y-2">
                    <div className="flex items-center justify-between bg-slate-50 p-2 rounded-lg">
                      <div className="flex items-center gap-2">
                         <div className="font-semibold text-slate-700 text-sm">{dayStr}</div>
                         {isHoliday && <span className="text-xs text-orange-500 font-bold px-1.5 py-0.5 bg-orange-100 rounded">FESTIVO</span>}
                      </div>
                      <div className="flex items-center gap-3">
                         <span className={`text-xs font-bold ${delta >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                           {delta > 0 ? '+' : ''}{delta.toFixed(2)}h
                         </span>
                         <span className="text-sm font-mono text-slate-900 bg-white px-2 py-0.5 rounded border border-slate-200">
                           Tot: {dayTotal.toFixed(2)}h
                         </span>
                      </div>
                    </div>

                    <div className="pl-4 space-y-3 border-l-2 border-slate-100 ml-2">
                      {daysSessions.sort((a,b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()).map(session => (
                        <div key={session.id} className="relative pb-1">
                            <div className="flex justify-between mb-0.5">
                              <span className="text-xs text-slate-500 font-medium">
                                {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                                {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '...'}
                              </span>
                            </div>
                            <div className="text-sm text-slate-600">
                              {session.activityRefined || session.activityRaw || <span className="text-slate-400 italic text-xs">Nessuna descrizione</span>}
                            </div>
                        </div>
                      ))}
                    </div>
                  </div>
                 );
              })}
              {sessions.length === 0 && <div className="text-center text-slate-400 text-sm">Nessuno storico disponibile.</div>}
            </div>
          </div>
        )}

        {/* --- SETTINGS VIEW --- */}
        {view === 'settings' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
            <h2 className="font-bold text-lg flex items-center gap-2"><Settings size={20} /> Impostazioni</h2>

            <div className="space-y-4">
              <h3 className="font-medium text-slate-800 text-sm uppercase tracking-wide">Orario di Lavoro Standard</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Lun - Gio</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.monThu}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, monThu: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Venerdì</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.fri}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, fri: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-slate-500 mb-1">Weekend / Festivi</label>
                  <div className="relative">
                    <input 
                      type="number" 
                      value={settings.schedule.satSun}
                      onChange={(e) => setSettings({...settings, schedule: {...settings.schedule, satSun: Number(e.target.value)}})}
                      className="w-full p-2 pl-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    />
                    <span className="absolute right-3 top-2 text-slate-400 text-sm">h</span>
                  </div>
                </div>
              </div>
              <div className="flex items-start gap-2 bg-slate-50 p-3 rounded-lg text-xs text-slate-600">
                <Info size={16} className="text-blue-500 shrink-0 mt-0.5" />
                <p>I giorni festivi italiani (Natale, Capodanno, ecc.) sono rilevati automaticamente e useranno l'orario "Weekend / Festivi". Le ore lavorate in questi giorni sono considerate interamente come straordinario nel monte ore.</p>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100">
              <h3 className="font-medium text-slate-900 mb-2">Dati</h3>
              <button 
                onClick={() => {
                  if(confirm('Cancellare tutti i dati? Questa azione è irreversibile.')) {
                    setSessions([]);
                    Storage.saveSessions([]);
                  }
                }}
                className="text-red-600 text-sm hover:underline flex items-center gap-1"
              >
                <Trash2 size={14} /> Cancella tutti i dati
              </button>
            </div>
          </div>
        )}

      </main>

      {/* Mobile Navigation */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 px-6 py-3 flex justify-between items-center z-20 md:hidden">
        <button 
          onClick={() => setView('dashboard')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Clock size={24} /> Home
        </button>
        <button 
          onClick={() => setView('history')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'history' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Calendar size={24} /> Storico
        </button>
        <button 
          onClick={() => setView('settings')}
          className={`flex flex-col items-center gap-1 text-xs font-medium ${view === 'settings' ? 'text-blue-600' : 'text-slate-400'}`}
        >
          <Settings size={24} /> Opzioni
        </button>
      </nav>

      {/* Desktop Navigation Hints (Hidden on mobile) */}
      <div className="hidden md:flex fixed top-4 right-4 z-20 gap-2">
         <button onClick={() => setView('dashboard')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'dashboard' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Dashboard</button>
         <button onClick={() => setView('history')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'history' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Storico</button>
         <button onClick={() => setView('settings')} className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors ${view === 'settings' ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-50'}`}>Opzioni</button>
      </div>

    </div>
  );
};

export default App;

export type SessionType = 'work' | 'ord_2025' | 'ord_2026' | 'lic_937' | 'rec_fest';

export interface WorkSession {
  id: string;
  startTime: string; // ISO string
  endTime: string | null; // ISO string
  type: SessionType; // New field to distinguish work from leave
  activityRaw: string;
  activityRefined: string;
  tags: string[];
}

export interface DailyStat {
  date: string; // YYYY-MM-DD
  totalHours: number;
  expectedHours: number;
  overtime: number; // Can be negative
}

export interface ScheduleSettings {
  monThu: number; // Target hours for Mon-Thu
  fri: number;    // Target hours for Fri
  satSun: number; // Target hours for Sat-Sun
}

export interface LeaveBalances {
  ord_2025: number; // Initial budget in hours
  ord_2026: number;
  lic_937: number;
  rec_fest: number;
}

export interface UserSettings {
  schedule: ScheduleSettings;
  leaveBalances: LeaveBalances; // Added balances
  hourlyRate?: number;
}

import { WorkSession, UserSettings } from '../types';

const SESSIONS_KEY = 'jobtrack_sessions';
const SETTINGS_KEY = 'jobtrack_settings';

// Default schedule: Mon-Thu 8.5h (08:00-16:30), Fri 4h (08:00-12:00), Weekend 0
const DEFAULT_SETTINGS: UserSettings = {
  schedule: {
    monThu: 8.5,
    fri: 4,
    satSun: 0
  },
  leaveBalances: {
    ord_2025: 0,
    ord_2026: 0,
    lic_937: 0,
    rec_fest: 0
  }
};

export const loadSessions = (): WorkSession[] => {
  try {
    const data = localStorage.getItem(SESSIONS_KEY);
    const sessions = data ? JSON.parse(data) : [];
    // Migration for existing sessions without type
    return sessions.map((s: any) => ({
      ...s,
      type: s.type || 'work'
    }));
  } catch (e) {
    console.error("Failed to load sessions", e);
    return [];
  }
};

export const saveSessions = (sessions: WorkSession[]) => {
  localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
};

export const loadSettings = (): UserSettings => {
  try {
    const data = localStorage.getItem(SETTINGS_KEY);
    if (!data) return DEFAULT_SETTINGS;

    const parsed = JSON.parse(data);

    // Merge with defaults to ensure new fields (like leaveBalances) exist
    return { 
      ...DEFAULT_SETTINGS, 
      ...parsed,
      leaveBalances: { ...DEFAULT_SETTINGS.leaveBalances, ...(parsed.leaveBalances || {}) }
    };
  } catch (e) {
    return DEFAULT_SETTINGS;
  }
};

export const saveSettings = (settings: UserSettings) => {
  localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
};

import { UserSettings, WorkSession } from '../types';

// Fixed Italian Holidays (DD-MM)
const FIXED_HOLIDAYS = new Set([
  '01-01', // Capodanno
  '01-06', // Epifania
  '04-25', // Liberazione
  '05-01', // Festa del Lavoro
  '06-02', // Repubblica
  '08-15', // Ferragosto
  '11-01', // Ognissanti
  '12-08', // Immacolata
  '12-25', // Natale
  '12-26', // Santo Stefano
]);

export const isHoliday = (date: Date): boolean => {
  const dayMonth = date.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' }).replace('/', '-');
  return FIXED_HOLIDAYS.has(dayMonth);
};

export const getTargetHoursForDate = (dateString: string, settings: UserSettings): number => {
  const date = new Date(dateString);
  const day = date.getDay(); // 0 = Sun, 1 = Mon, ... 6 = Sat

  // Check Holidays first
  if (isHoliday(date)) {
    return settings.schedule.satSun; // Treat holidays like weekends (usually 0)
  }

  // Sunday (0) or Saturday (6)
  if (day === 0 || day === 6) {
    return settings.schedule.satSun;
  }

  // Friday (5)
  if (day === 5) {
    return settings.schedule.fri;
  }

  // Mon (1) - Thu (4)
  return settings.schedule.monThu;
};

/**
 * Calculates the total cumulative balance (Monte Ore) based on all past completed sessions.
 * Positive value means overtime accumulated. Negative value means hours owed.
 * 
 * NOTE: Leave sessions ('ord_2025', etc.) count as POSITIVE duration towards the daily target,
 * effectively neutralizing the target for that day (or part of it).
 */
export const calculateTotalBalance = (sessions: WorkSession[], settings: UserSettings): number => {
  const sessionsByDay = new Map<string, number>();

  // 1. Group total duration by unique day (YYYY-MM-DD)
  sessions.forEach(session => {
    if (!session.endTime) return; 

    // Use ISO date part YYYY-MM-DD
    const dateKey = new Date(session.startTime).toLocaleDateString('sv-SE'); 

    const duration = (new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60);
    sessionsByDay.set(dateKey, (sessionsByDay.get(dateKey) || 0) + duration);
  });

  let balance = 0;

  // 2. Iterate each day worked and compare against target
  sessionsByDay.forEach((hoursWorkedAndLeave, dateStr) => {
    const target = getTargetHoursForDate(dateStr, settings);
    balance += (hoursWorkedAndLeave - target);
  });

  return balance;
};

/**
 * Calculates used hours for specific leave types
 */
export const calculateUsedLeave = (sessions: WorkSession[]) => {
  const usage = {
    ord_2025: 0,
    ord_2026: 0,
    lic_937: 0,
    rec_fest: 0
  };

  sessions.forEach(s => {
    if (!s.endTime || s.type === 'work') return;
    const duration = (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);

    if (s.type in usage) {
      usage[s.type as keyof typeof usage] += duration;
    }
  });

  return usage;
};

