// Fixed Italian Holidays (DD-MM)
const FIXED_HOLIDAYS = new Set([
  '01-01', // Capodanno
  '01-06', // Epifania
  '04-25', // Liberazione
  '05-01', // Festa del Lavoro
  '06-02', // Repubblica
  '08-15', // Ferragosto
  '11-01', // Ognissanti
  '12-08', // Immacolata
  '12-25', // Natale
  '12-26', // Santo Stefano
]);

export const isHoliday = (date: Date): boolean => {
  const dayMonth = date.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' }).replace('/', '-');
  return FIXED_HOLIDAYS.has(dayMonth);
};

export const getTargetHoursForDate = (dateString: string, settings: UserSettings): number => {
  const date = new Date(dateString);
  const day = date.getDay(); // 0 = Sun, 1 = Mon, ... 6 = Sat

  // Check Holidays first
  if (isHoliday(date)) {
    return settings.schedule.satSun; // Treat holidays like weekends (usually 0)
  }

  // Sunday (0) or Saturday (6)
  if (day === 0 || day === 6) {
    return settings.schedule.satSun;
  }

  // Friday (5)
  if (day === 5) {
    return settings.schedule.fri;
  }

  // Mon (1) - Thu (4)
  return settings.schedule.monThu;
};

/**
 * Calculates the total cumulative balance (Monte Ore) based on all past completed sessions.
 * Positive value means overtime accumulated. Negative value means hours owed.
 * 
 * NOTE: Leave sessions ('ord_2025', etc.) count as POSITIVE duration towards the daily target,
 * effectively neutralizing the target for that day (or part of it) regarding overtime calculation.
 */
export const calculateTotalBalance = (sessions: WorkSession[], settings: UserSettings): number => {
  const sessionsByDay = new Map<string, number>();

  // 1. Group total duration by unique day (YYYY-MM-DD)
  sessions.forEach(session => {
    if (!session.endTime) return; 

    // Use ISO date part YYYY-MM-DD
    const dateKey = new Date(session.startTime).toLocaleDateString('sv-SE'); 

    const duration = (new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60);
    sessionsByDay.set(dateKey, (sessionsByDay.get(dateKey) || 0) + duration);
  });

  let balance = 0;

  // 2. Iterate each day worked and compare against target
  sessionsByDay.forEach((hoursWorkedAndLeave, dateStr) => {
    const target = getTargetHoursForDate(dateStr, settings);
    balance += (hoursWorkedAndLeave - target);
  });

  return balance;
};

/**
 * Calculates used DAYS for specific leave types.
 * Logic: Duration / TargetHoursForThatDay = DaysUsed.
 * E.g., On a 4h Friday, taking 4h off = 1 Day.
 *       On an 8h Monday, taking 4h off = 0.5 Days.
 */
export const calculateUsedLeave = (sessions: WorkSession[], settings: UserSettings) => {
  const usage = {
    ord_2025: 0,
    ord_2026: 0,
    lic_937: 0,
    rec_fest: 0
  };

  sessions.forEach(s => {
    if (!s.endTime || s.type === 'work') return;

    // Calculate duration in hours
    const duration = (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);

    // Get target hours for that specific date to determine what "1 Day" means
    const targetForDay = getTargetHoursForDate(s.startTime, settings);

    if (s.type in usage) {
      // If target is 0 (e.g., booked leave on a sunday/holiday?), avoid division by zero.
      // Otherwise, calculate fraction of day.
      const days = targetForDay > 0 ? duration / targetForDay : 0;
      usage[s.type as keyof typeof usage] += days;
    }
  });

  return usage;
};

