};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Save, Clock, Calendar, BarChart2, Settings, Sparkles, Trash2, Info, TrendingUp, TrendingDown, Briefcase, Palmtree, Award, RotateCcw, BatteryCharging } from 'lucide-react';
import { WorkSession, UserSettings, SessionType } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import * as DateService from './services/dateService';
import WorkChart from './components/WorkChart';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [settings, setSettings] = useState<UserSettings>({ 
    schedule: { monThu: 8.5, fri: 4, satSun: 0 },
    leaveBalances: { ord_2025: 0, ord_2026: 0, lic_937: 0, rec_fest: 0 }
  });

  const [view, setView] = useState<'dashboard' | 'history' | 'settings'>('dashboard');

  // Manual Entry State
  const [entryDate, setEntryDate] = useState(new Date().toISOString().split('T')[0]);
  const [entryStart, setEntryStart] = useState('08:00');
  const [entryEnd, setEntryEnd] = useState('16:30');
  const [entryType, setEntryType] = useState<SessionType>('work');
  const [entryActivity, setEntryActivity] = useState('');

  // UI State for Activity Editing / AI
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [activityText, setActivityText] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiReport, setAiReport] = useState<string | null>(null);

  // Initialize
  useEffect(() => {
    const loadedSessions = Storage.loadSessions();
    const loadedSettings = Storage.loadSettings();
    setSessions(loadedSessions);
    setSettings(loadedSettings);
  }, []);

  // Persist sessions whenever they change
  useEffect(() => {
    Storage.saveSessions(sessions);
  }, [sessions]);

  // Persist settings
  useEffect(() => {
    Storage.saveSettings(settings);
  }, [settings]);

  // --- Logic ---

  const handleAddManualSession = async () => {
    if (!entryDate) return;

    let startDateTime: Date;
    let endDateTime: Date;

    if (entryType === 'work') {
      if (!entryStart || !entryEnd) return;
      startDateTime = new Date(`${entryDate}T${entryStart}`);
      endDateTime = new Date(`${entryDate}T${entryEnd}`);

      if (endDateTime <= startDateTime) {
        alert("L'orario di fine deve essere successivo all'inizio.");
        return;
      }
    } else if (entryType === 'rec_comp') {
       // Recupero Compensativo: Save with 0 duration.
       // The dateService handles the logic to deduct full target from Monte Ore.
       startDateTime = new Date(`${entryDate}T09:00:00`);
       endDateTime = new Date(`${entryDate}T09:00:00`);
    } else {
      // Standard Leave (Ord/Lic): 
      // We save with duration = target so the visual chart shows a "Full" day (green).
      // However, dateService logic explicitly calculates balance change as 0 for these types.
      const targetHours = DateService.getTargetHoursForDate(entryDate, settings);
      startDateTime = new Date(`${entryDate}T09:00:00`);
      endDateTime = new Date(startDateTime.getTime() + targetHours * 60 * 60 * 1000);
    }

    const newSession: WorkSession = {
      id: crypto.randomUUID(),
      startTime: startDateTime.toISOString(),
      endTime: endDateTime.toISOString(),
      type: entryType,
      activityRaw: entryActivity,
      activityRefined: entryActivity,
      tags: []
    };

    setSessions(prev => [...prev, newSession]);

    // Reset activity but keep times/date for easier sequential entry
    setEntryActivity('');

    // AI Refinement Trigger (only for actual work)
    if (entryActivity && entryType === 'work') {
       setIsAiLoading(true);
       try {
         const refined = await GeminiService.refineActivityText(entryActivity);
         setSessions(prev => prev.map(s => s.id === newSession.id ? { ...s, activityRefined: refined } : s));
       } catch(e) { console.error(e) }
       setIsAiLoading(false);
    }
  };

  const handleSaveActivity = async (sessionId: string) => {
    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: activityText } : s
    ));
    setEditingSessionId(null);
    setActivityText('');
  };

  const handleRefineWithAI = async (sessionId: string) => {
    setIsAiLoading(true);
    const refined = await GeminiService.refineActivityText(activityText);

    setSessions(prev => prev.map(s => 
      s.id === sessionId ? { ...s, activityRaw: activityText, activityRefined: refined } : s
    ));
    setActivityText(refined); 
    setIsAiLoading(false);
  };

  const handleDeleteSession = (id: string) => {
    if (confirm("Sei sicuro di voler eliminare questa sessione?")) {
      setSessions(prev => prev.filter(s => s.id !== id));
    }
  };

  const generateReport = async () => {
    setIsAiLoading(true);
    const report = await GeminiService.generateWeeklyReport(sessions.filter(s => s.type === 'work'));
    setAiReport(report);
    setIsAiLoading(false);
  };

  // --- Derived Data ---

  const todayDateStr = new Date().toISOString();
  const todayLocale = new Date().toLocaleDateString('it-IT');

  // Total Balance (Monte Ore - Straordinario)
  const totalBalance = DateService.calculateTotalBalance(sessions, settings);

  // Leave Calculations (in Integers/Days)
  const usedLeaveDays = DateService.calculateUsedLeave(sessions);

  const balanceOrd2025 = settings.leaveBalances.ord_2025 - usedLeaveDays.ord_2025;
  const balanceOrd2026 = settings.leaveBalances.ord_2026 - usedLeaveDays.ord_2026;
  const balanceLic937 = settings.leaveBalances.lic_937 - usedLeaveDays.lic_937;
  const balanceRecFest = settings.leaveBalances.rec_fest - usedLeaveDays.rec_fest;

  // Grouped History for Display
  const sessionsByDay = sessions.reduce((acc, session) => {
    const day = new Date(session.startTime).toLocaleDateString('it-IT');
    if (!acc[day]) acc[day] = [];
    acc[day].push(session);
    return acc;
  }, {} as Record<string, WorkSession[]>);

  const sortedDays = Object.keys(sessionsByDay).sort((a, b) => {
    const [da, ma, ya] = a.split('/').map(Number);
    const [db, mb, yb] = b.split('/').map(Number);
    return new Date(yb, mb-1, db).getTime() - new Date(ya, ma-1, da).getTime();
  });

  const isEntryDateHoliday = DateService.isHoliday(new Date(entryDate));

  // Helper to get color for session type
  const getTypeColor = (type: SessionType) => {
    switch(type) {
      case 'work': return 'text-slate-700 bg-slate-50 border-slate-200';
      case 'ord_2025': return 'text-blue-700 bg-blue-50 border-blue-200';
      case 'ord_2026': return 'text-indigo-700 bg-indigo-50 border-indigo-200';
      case 'lic_937': return 'text-purple-700 bg-purple-50 border-purple-200';
      case 'rec_fest': return 'text-orange-700 bg-orange-50 border-orange-200';
      case 'rec_comp': return 'text-teal-700 bg-teal-50 border-teal-200';
      default: return 'text-slate-700';
    }
  };

  const getTypeLabel = (type: SessionType) => {
    switch(type) {
      case 'work': return 'Lavoro Ordinario';
      case 'ord_2025': return 'Ordinaria 2025';
      case 'ord_2026': return 'Ordinaria 2026';
      case 'lic_937': return 'Licenza 937';
      case 'rec_fest': return 'Recupero Fest.';
      case 'rec_comp': return 'Recupero Comp.';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 md:pb-0">

      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-blue-600 text-white p-1.5 rounded-lg">
              <Clock size={20} strokeWidth={2.5} />
            </div>
            <h1 className="font-bold text-xl text-slate-900 tracking-tight">JobTrack AI</h1>
          </div>
          <div className="text-xs font-medium px-2 py-1 bg-slate-100 rounded text-slate-500">
            {todayLocale}
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto p-4 space-y-6">

        {/* --- DASHBOARD VIEW --- */}
        {view === 'dashboard' && (
          <>
            {/* Horizontal Scroll Cards */}
            <div className="overflow-x-auto pb-2 -mx-4 px-4 scrollbar-hide">
              <div className="flex gap-3 min-w-max">

                {/* 1. Ordinaria 2025 */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 w-40 flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-blue-600 mb-2">
                    <Palmtree size={18} />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Ord. 2025</span>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-slate-800">{balanceOrd2025.toFixed(0)} gg</div>
                    <div className="text-[10px] text-slate-400">Su {settings.leaveBalances.ord_2025} gg iniziali</div>
                  </div>
                </div>

                {/* 2. Ordinaria 2026 */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 w-40 flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-indigo-600 mb-2">
                    <Palmtree size={18} />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Ord. 2026</span>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-slate-800">{balanceOrd2026.toFixed(0)} gg</div>
                    <div className="text-[10px] text-slate-400">Su {settings.leaveBalances.ord_2026} gg iniziali</div>
                  </div>
                </div>

                {/* 3. Licenza 937 */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 w-40 flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-purple-600 mb-2">
                    <Award size={18} />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Lic. 937</span>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-slate-800">{balanceLic937.toFixed(0)} gg</div>
                    <div className="text-[10px] text-slate-400">Su {settings.leaveBalances.lic_937} gg iniziali</div>
                  </div>
                </div>

                {/* 4. Recupero Festività */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 w-40 flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-orange-600 mb-2">
                    <RotateCcw size={18} />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Rec. Fest.</span>
                  </div>
                  <div>
                    <div className="text-2xl font-bold text-slate-800">{balanceRecFest.toFixed(0)} gg</div>
                    <div className="text-[10px] text-slate-400">Su {settings.leaveBalances.rec_fest} gg iniziali</div>
                  </div>
                </div>

                {/* 5. Straordinario (Monte Ore) renamed to Rec comp. */}
                <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 w-44 flex flex-col justify-between relative overflow-hidden">
                   <div className={`absolute top-0 right-0 w-1.5 h-full ${totalBalance >= 0 ? 'bg-green-500' : 'bg-red-500'}`}></div>
                   <div className="flex items-center gap-2 text-slate-600 mb-2">
                    <Briefcase size={18} />
                    <span className="text-[10px] font-bold uppercase tracking-wider text-slate-500">Rec comp.</span>
                  </div>
                  <div>
                    <div className={`text-2xl font-bold ${totalBalance >= 0 ? 'text-green-700' : 'text-red-600'}`}>
                      {totalBalance > 0 ? '+' : ''}{totalBalance.toFixed(2)}h
                    </div>
                    <div className="text-[10px] text-slate-400">Saldo accumulato</div>
                  </div>
                </div>

              </div>
            </div>

            {/* Manual Entry Card */}
            <div className={`bg-white rounded-2xl shadow-sm border p-6 relative transition-colors duration-300 ${entryType === 'work' ? 'border-slate-200' : 'border-blue-200 ring-1 ring-blue-50'}`}>
              <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 border-b border-slate-100 pb-3">
                <Plus size={20} className={entryType === 'work' ? "text-blue-600" : "text-indigo-600"} /> 
                {entryType === 'work' ? 'Registra Lavoro' : 'Registra Assenza'}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-5">
                <div className="md:col-span-2">
                  <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Tipo Attività</label>
                  <select 
                    value={entryType}
                    onChange={(e) => setEntryType(e.target.value as SessionType)}
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                  >
                    <option value="work">💼 Lavoro Ordinario</option>
                    <option disabled className="text-slate-300">--- Ferie e Permessi (Non scala ore) ---</option>
                    <option value="ord_2025">🌴 Ordinaria 2025 (gg)</option>
                    <option value="ord_2026">🌴 Ordinaria 2026 (gg)</option>
                    <option value="lic_937">🎖️ Licenza 937 (gg)</option>
                    <option value="rec_fest">🔄 Recupero Festività (gg)</option>
                    <option disabled className="text-slate-300">--- Utilizzo Straordinario ---</option>
                    <option value="rec_comp">⚡ Recupero Compensativo (Scala Monte Ore)</option>
                  </select>
                </div>

                <div>
                   <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Data</label>
                   <input 
                    type="date" 
                    value={entryDate} 
                    onChange={e => setEntryDate(e.target.value)} 
                    className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                   />
                   {isEntryDateHoliday && (
                     <div className="text-xs text-orange-600 font-medium mt-1 flex items-center gap-1">
                       <Sparkles size={10} /> Giorno Festivo
                     </div>
                   )}
                </div>

                {entryType === 'work' ? (
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Inizio</label>
                      <input 
                        type="time" 
                        value={entryStart} 
                        onChange={e => setEntryStart(e.target.value)} 
                        className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Fine</label>
                      <input 
                        type="time" 
                        value={entryEnd} 
                        onChange={e => setEntryEnd(e.target.value)} 
                        className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none font-medium text-slate-700"
                      />
                    </div>
                  </div>
                ) : (
                  <div className={`flex items-center justify-center border rounded-lg font-medium text-sm ${entryType === 'rec_comp' ? 'bg-teal-50 border-teal-100 text-teal-700' : 'bg-indigo-50 border-indigo-100 text-indigo-700'}`}>
                     <span className="flex items-center gap-2">
                       {entryType === 'rec_comp' ? <BatteryCharging size={16} /> : <Clock size={16} />}
                       {entryType === 'rec_comp' ? 'Assenza con Recupero Ore' : 'Intera Giornata'}
                     </span>
                  </div>
                )}
              </div>

              <div className="mb-5">
                  <label className="block text-xs font-semibold text-slate-500 mb-1.5 uppercase">Note / Descrizione</label>
                  <input 
                    type="text" 
                    value={entryActivity} 
                    onChange={e => setEntryActivity(e.target.value)}
                    placeholder={entryType === 'work' ? "Es. Sviluppo funzionalità login..." : "Es. Giornata di riposo"} 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none text-sm placeholder:text-slate-400"
                  />
              </div>

              <button 
                onClick={handleAddManualSession}
                className={`w-full text-white font-semibold py-3 rounded-xl shadow-lg active:scale-[0.99] transition-all flex items-center justify-center gap-2 
                  ${entryType === 'work' ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-200' : 
                    entryType === 'rec_comp' ? 'bg-teal-600 hover:bg-teal-700 shadow-teal-200' : 
                    'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'}`}
              >
                <Save size={18} /> {entryType === 'work' ? 'Registra Lavoro' : 'Conferma Assenza'}
              </button>
            </div>

            {/* Stats Chart */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="font-semibold text-slate-800 flex items-center gap-2">
                  <BarChart2 size={18} /> Grafico Settimanale
                </h2>
              </div>
              <WorkChart sessions={sessions} settings={settings} />
            </div>

            {/* Recent Sessions List */}
            <div className="space-y-4">
               <div className="flex items-center justify-between">
                <h3 className="font-semibold text-slate-800">Ultimi Movimenti</h3>
                <button 
                  onClick={generateReport}
                  disabled={isAiLoading}
                  className="text-xs flex items-center gap-1 text-purple-600 hover:text-purple-700 font-medium disabled:opacity-50"
                >
                  <Sparkles size={14} /> {isAiLoading ? 'Analisi...' : 'Report AI'}
                </button>
               </div>

               {aiReport && (
                 <div className="bg-purple-50 border border-purple-100 p-4 rounded-xl text-sm text-purple-900 leading-relaxed mb-4 animate-in fade-in slide-in-from-top-2">
                   <h4 className="font-bold mb-1 flex items-center gap-2"><Sparkles size={12} /> Insight Gemini</h4>
                   {aiReport}
                 </div>
               )}

               <div className="space-y-3">
                {sessions.slice().reverse().slice(0, 5).map(session => (
                  <div key={session.id} className={`border rounded-xl p-4 flex flex-col gap-3 transition-colors group ${getTypeColor(session.type)}`}>
                    <div className="flex justify-between items-start">
                      <div>
                        <div className="flex items-center gap-2 mb-1">
                          <span className={`text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded bg-white/50 border border-black/5`}>
                             {getTypeLabel(session.type)}
                          </span>
                        </div>
                        <div className="text-sm font-medium opacity-90">
                          {session.type === 'work' ? (
                            <>
                              {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                              {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : ' ...'}
                            </>
                          ) : (
                            <span>Giornata Intera</span>
                          )}
                        </div>
                        <div className="text-xs opacity-60 mt-0.5">
                          {new Date(session.startTime).toLocaleDateString()}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                         {session.type === 'work' && (
                           <span className="text-xs font-mono bg-white/50 px-2 py-1 rounded opacity-80 font-bold">
                             {session.endTime 
                               ? ((new Date(session.endTime).getTime() - new Date(session.startTime).getTime()) / (1000 * 60 * 60)).toFixed(2) + 'h'
                               : 'N/A'}
                           </span>
                         )}
                         <button onClick={() => handleDeleteSession(session.id)} className="opacity-0 group-hover:opacity-100 transition-opacity p-1 hover:text-red-600">
                           <Trash2 size={14} />
                         </button>
                      </div>
                    </div>

                    <div className="relative">
                       {editingSessionId === session.id ? (
                         <div className="space-y-2">
                           <textarea
                             value={activityText}
                             onChange={(e) => setActivityText(e.target.value)}
                             placeholder="Modifica..."
                             className="w-full text-sm p-3 rounded-lg border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                             rows={2}
                             autoFocus
                           />
                           <div className="flex gap-2 justify-end">
                             {session.type === 'work' && (
                               <button 
                                 onClick={() => handleRefineWithAI(session.id)}
                                 disabled={isAiLoading || !activityText}
                                 className="text-xs bg-purple-100 text-purple-700 px-3 py-1.5 rounded-md font-medium flex items-center gap-1 hover:bg-purple-200 disabled:opacity-50"
                               >
                                 <Sparkles size={12} /> AI
                               </button>
                             )}
                             <button 
                               onClick={() => handleSaveActivity(session.id)}
                               className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium hover:bg-blue-700"
                             >
                               Salva
                             </button>
                           </div>
                         </div>
                       ) : (
                         <div 
                           onClick={() => {
                             setEditingSessionId(session.id);
                             setActivityText(session.activityRefined || session.activityRaw);
                           }}
                           className={`text-sm cursor-pointer hover:bg-white/50 p-2 -ml-2 rounded-lg transition-colors ${!session.activityRefined && !session.activityRaw ? 'opacity-50 italic' : 'opacity-80'}`}
                         >
                           {session.activityRefined || session.activityRaw || "Nessuna nota"}
                         </div>
                       )}
                    </div>
                  </div>
                ))}
                {sessions.length === 0 && (
                  <div className="text-center py-10 text-slate-400 text-sm">Nessuna registrazione presente.</div>
                )}
               </div>
            </div>
          </>
        )}

        {/* --- HISTORY VIEW --- */}
        {view === 'history' && (
          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h2 className="font-bold text-lg mb-6 flex items-center gap-2"><Calendar size={20} /> Storico Completo</h2>
            <div className="space-y-6">
              {sortedDays.reverse().map(dayStr => {
                 const daysSessions = sessionsByDay[dayStr];
                 const dayTotal = daysSessions.reduce((acc, s) => {
                   // Calculate duration ONLY for standard work sessions.
                   // Leave days have 0 "worked" hours in this context, although they neutralize the debt in the main calc.
                   if (s.type === 'work' && s.endTime) {
                     return acc + (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
                   }
                   return acc;
                 }, 0);

                 const [d, m, y] = dayStr.split('/').map(Number);
                 const dateObj = new Date(y, m-1, d);
                 const target = DateService.getTargetHoursForDate(dateObj.toISOString(), settings);

                 // Display logic for daily delta
                 const hasLeave = daysSessions.some(s => ['ord_2025', 'ord_2026', 'lic_937', 'rec_fest'].includes(s.type));
                 const hasRecComp = daysSessions.some(s => s.type === 'rec_comp');

                 let deltaDisplay = 0;
                 if (hasLeave) deltaDisplay = 0;
                 else if (hasRecComp) deltaDisplay = -target;
                 else deltaDisplay = dayTotal - target;

                 const isHoliday = DateService.isHoliday(dateObj);

                 return (
                  <div key={dayStr} className="space-y-2">
                    <div className="flex items-center justify-between bg-slate-50 p-2 rounded-lg">
                      <div className="flex items-center gap-2">
                         <div className="font-semibold text-slate-700 text-sm">{dayStr}</div>
                         {isHoliday && <span className="text-xs text-orange-500 font-bold px-1.5 py-0.5 bg-orange-100 rounded">FESTIVO</span>}
                      </div>
                      <div className="flex items-center gap-3">
                         <span className={`text-xs font-bold ${deltaDisplay >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                           {deltaDisplay > 0 ? '+' : ''}{deltaDisplay.toFixed(2)}h
                         </span>
                         <span className="text-sm font-mono text-slate-900 bg-white px-2 py-0.5 rounded border border-slate-200">
                           Lav: {dayTotal.toFixed(2)}h
                         </span>
                      </div>
                    </div>

                    <div className="pl-4 space-y-3 border-l-2 border-slate-100 ml-2">
                      {daysSessions.sort((a,b) => new Date(b.startTime).getTime() - new Date(a.startTime).getTime()).map(session => (
                        <div key={session.id} className="relative pb-1">
                            <div className="flex justify-between mb-0.5">
                              <span className="text-xs text-slate-500 font-medium flex items-center gap-2">
                                <span className={`w-2 h-2 rounded-full ${session.type === 'work' ? 'bg-slate-400' : 'bg-blue-400'}`}></span>
                                {session.type === 'work' ? (
                                   <>
                                    {new Date(session.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                                    {session.endTime ? new Date(session.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '...'}
                                   </>
                                ) : (
                                   <span>Giornata Intera</span>
                                )}
                              </span>
                              {session.type !== 'work' && (
                                <span className="text-[10px] uppercase font-bold text-blue-600 bg-blue-50 px-1.5 rounded">{getTypeLabel(session.type)}</span>
                              )}
                            </div>
                            <div className="text-sm text-slate-600">
                              {session.activityRefined || session.activityRaw || <span className="text-slate-400 italic text-xs">Nessuna descrizione</span>}
                            </div>
                        </div>
                      ))}
                    </div>
                  </div>
                 );
              })}
              {sessions.length === 0 && <div className="text-center text-slate-400 text-sm">Nessuno storico disponibile.</div>}
            </div>
          </div>
        )}

