// Fixed Italian Holidays (DD-MM)
const FIXED_HOLIDAYS = new Set([
  '01-01', // Capodanno
  '01-06', // Epifania
  '04-25', // Liberazione
  '05-01', // Festa del Lavoro
  '06-02', // Repubblica
  '08-15', // Ferragosto
  '11-01', // Ognissanti
  '12-08', // Immacolata
  '12-25', // Natale
  '12-26', // Santo Stefano
]);

export const isHoliday = (date: Date): boolean => {
  const dayMonth = date.toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit' }).replace('/', '-');
  return FIXED_HOLIDAYS.has(dayMonth);
};

export const getTargetHoursForDate = (dateString: string, settings: UserSettings): number => {
  const date = new Date(dateString);
  const day = date.getDay(); // 0 = Sun, 1 = Mon, ... 6 = Sat

  // Check Holidays first
  if (isHoliday(date)) {
    return settings.schedule.satSun; // Treat holidays like weekends (usually 0)
  }

  // Sunday (0) or Saturday (6)
  if (day === 0 || day === 6) {
    return settings.schedule.satSun;
  }

  // Friday (5)
  if (day === 5) {
    return settings.schedule.fri;
  }

  // Mon (1) - Thu (4)
  return settings.schedule.monThu;
};

/**
 * Calculates the total cumulative balance (Monte Ore).
 * 
 * Logic:
 * 1. 'work': Actual Duration - Target = Balance Change (Positive or Negative).
 * 2. 'ord', 'lic', 'rec_fest', 'com_log': Neutral (Balance Change = 0). It counts as a day taken, but doesn't affect hours.
 * 3. 'rec_comp': You are absent using overtime. Balance Change = -Target (e.g. -8.5h).
 */
export const calculateTotalBalance = (sessions: WorkSession[], settings: UserSettings): number => {
  const sessionsByDay = new Map<string, WorkSession[]>();

  // 1. Group sessions by unique day
  sessions.forEach(session => {
    // Use ISO date part YYYY-MM-DD
    const dateKey = new Date(session.startTime).toLocaleDateString('sv-SE'); 
    if (!sessionsByDay.has(dateKey)) {
      sessionsByDay.set(dateKey, []);
    }
    sessionsByDay.get(dateKey)!.push(session);
  });

  let balance = 0;

  // 2. Iterate each day
  sessionsByDay.forEach((daySessions, dateStr) => {
    const target = getTargetHoursForDate(dateStr, settings);

    // Check session types for this day
    const hasLeave = daySessions.some(s => ['ord_2025', 'ord_2026', 'lic_937', 'rec_fest', 'com_log'].includes(s.type));
    const hasRecComp = daySessions.some(s => s.type === 'rec_comp');

    if (hasLeave) {
      // If taking formal leave (or Com log), it neutralizes the target. Balance change is 0.
      balance += 0; 
    } else if (hasRecComp) {
      // If taking Compensatory Recovery, we deduct the full target from the balance.
      // Example: Absent on Monday (-8.5h from Overtime bank).
      balance -= target;
    } else {
      // Standard Work Day (or partial work)
      // Calculate total duration of work sessions
      let dailyWorkDuration = 0;
      daySessions.forEach(s => {
        if (s.type === 'work' && s.endTime) {
          dailyWorkDuration += (new Date(s.endTime).getTime() - new Date(s.startTime).getTime()) / (1000 * 60 * 60);
        }
      });

      // Balance = Worked - Target
      // Examples: 
      // Worked 10h, Target 8.5h -> +1.5h to Monte Ore
      // Worked 4h, Target 8.5h -> -4.5h from Monte Ore
      balance += (dailyWorkDuration - target);
    }
  });

  return balance;
};

/**
 * Calculates used DAYS for specific leave types.
 * Logic: 1 Session = 1 Day (Integer Unit).
 */
export const calculateUsedLeave = (sessions: WorkSession[]) => {
  const usage = {
    ord_2025: 0,
    ord_2026: 0,
    lic_937: 0,
    rec_fest: 0,
    com_log: 0
  };

  sessions.forEach(s => {
    if (s.type === 'work' || s.type === 'rec_comp') return;

    if (s.type in usage) {
      // Treat every non-work session as 1 full unit (day)
      usage[s.type as keyof typeof usage] += 1;
    }
  });

  return usage;
};

