                                        </span>
                                        {session.type !== 'work' && (
                                            <span className={`text-[10px] uppercase font-bold px-1.5 rounded ${session.type === 'com_log' ? 'text-pink-600 bg-pink-50' : 'text-blue-600 bg-blue-50'}`}>{getTypeLabel(session.type)}</span>
                                        )}
                                        </div>
