  const [view, setView] = useState<'dashboard' | 'history' | 'operations' | 'settings'>('dashboard');

  // Manual Entry State
  // Use 'fr-CA' locale hack to get YYYY-MM-DD in local time
  const [entryDate, setEntryDate] = useState(new Date().toLocaleDateString('fr-CA'));
