    if (!file) return;

    if (file.size > 2 * 1024 * 1024) { // 2MB limit
      alert("L'immagine è troppo grande (Max 2MB).");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      setSettings(prev => ({ ...prev, logoUrl: base64String }));
