  // Use currentDate state to derived today's info
  const todayDateStr = currentDate.toISOString();
  const todayLocale = currentDate.toLocaleDateString('it-IT', { 
    weekday: 'short', 
    day: 'numeric', 
    month: 'long', 
    year: 'numeric' 
  });
