import React, { useState, useEffect } from 'react';
import { Plus, Save, Clock, Calendar, BarChart2, Settings, Sparkles, Trash2, Info, TrendingUp, TrendingDown, Briefcase, Palmtree, Award, RotateCcw, BatteryCharging, FileText, Upload, Image as ImageIcon, MapPin, UserCheck, Pencil, X, ArrowRight } from 'lucide-react';
import { WorkSession, UserSettings, SessionType } from './types';
import * as Storage from './services/storageService';
import * as GeminiService from './services/geminiService';
import * as DateService from './services/dateService';
import WorkChart from './components/WorkChart';

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<WorkSession[]>([]);
  const [settings, setSettings] = useState<UserSettings>({ 
    schedule: { monThu: 8.5, fri: 4, satSun: 0 },
