                      </div>
                      <div className="relative z-10">
                        <div className="text-2xl font-bold">{balance.toFixed(0)} <span className="text-sm opacity-80 font-medium">gg</span></div>
                        <div className="text-[10px] opacity-70">Su {initial} gg</div>
                      </div>
                    </div>
